  const arrowStartX  = xScale(Math.max(MIN_VAL, Math.min(MAX_VAL, start)));
  const arrowEndX    = xScale(visibleResult);
  const ARROW_Y      = LINE_Y - 22;
  const isOutOfRange = result &lt; MIN_VAL || result &gt; MAX_VAL;

  if (change !== 0) {
    const colour = change &gt; 0 ? "#0d9488" : "#d97706";
    svg.append("line")
      .attr("x1", arrowStartX).attr("y1", ARROW_Y)
      .attr("x2", arrowEndX).attr("y2", ARROW_Y)
      .attr("stroke", colour).attr("stroke-width", 2.5);

    // Arrowhead at end
    const dir = change &gt; 0 ? 1 : -1;
    svg.append("path")
      .attr("d", `M${arrowEndX},${ARROW_Y} L${arrowEndX - dir * 8},${ARROW_Y - 5} L${arrowEndX - dir * 8},${ARROW_Y + 5} Z`)
      .attr("fill", colour);
  }

  // Start position dot
  svg.append("circle")
    .attr("cx", arrowStartX).attr("cy", LINE_Y)
    .attr("r", 7)
    .attr("fill", "#4b5563")
    .attr("stroke", "#fff").attr("stroke-width", 1.5);

  svg.append("text")
    .attr("x", arrowStartX).attr("cy", LINE_Y)
    .attr("y", LINE_Y - 12)
    .attr("text-anchor", "middle")
    .attr("fill", "#374151").attr("font-size", "11px").attr("font-weight", "600")
    .text(start);

  // Result position dot
  const resultColour = result &gt; 0 ? "#0d9488" : result &lt; 0 ? "#d97706" : "#4b5563";
  svg.append("circle")
    .attr("cx", xScale(visibleResult)).attr("cy", LINE_Y)
    .attr("r", 7)
    .attr("fill", resultColour)
    .attr("stroke", "#fff").attr("stroke-width", 1.5);

  svg.append("text")
    .attr("x", xScale(visibleResult))
    .attr("y", LINE_Y + TICK_H + 28)
    .attr("text-anchor", "middle")
    .attr("fill", resultColour).attr("font-size", "11px").attr("font-weight", "700")
    .text(isOutOfRange ? `${result} (off scale)` : result);

  // Equation label
  const changeSign = change &gt;= 0 ? `+ ${change}` : `+ (${change})`;
  const eqLabel    = `${start}  ${changeSign}  =  ${result}`;
  svg.append("text")
    .attr("x", W / 2).attr("y", H - 6)
    .attr("text-anchor", "middle")
    .attr("fill", "#1f2937").attr("font-size", "13px").attr("font-weight", "700")
    .text(eqLabel);

  return svg.node();
}

7.2 The method
Addition and subtraction
Rewrite every subtraction as addition of the opposite: \(a - b = a + (-b)\).
Then use the number line: positive means move right, negative means move left. Your result is where you land.
Here, \(a\) and \(b\) are any numbers. This means one idea can handle both addition and subtraction.
Multiplication

Multiply the absolute values (ignore signs for now).
Count the number of negative factors.

Even number of negatives → positive result.
Odd number of negatives → negative result.


This means the size and the sign can be handled separately.
Division
Same rule: divide the absolute values, then apply the sign rule.
This means division follows the same sign pattern as multiplication.
Order of operations with signed numbers
Brackets first. Then signs attached to numbers. Then multiply/divide left to right. Then add/subtract left to right.
This means the sign belongs to the number it is attached to.






Why this works
Think of multiplication as repeated addition. \(3 \times (-4)\) means “add \(-4\) three times”: \((-4) + (-4) + (-4) = -12\). That gives \((+) \times (-) = (-)\).
For \((-) \times (-)\): \(-3 \times (-4)\) means “add \(-4\) negative three times.” Adding a negative thing a negative number of times is removing it — which is positive. The algebraic proof uses the distributive law: \(0 = (-3)(4 + (-4)) = (-3)(4) + (-3)(-4) = -12 + (-3)(-4)\), so \((-3)(-4) = 12\).




