  svg.append("line")
    .attr("x1", PAD).attr("y1", AXIS_Y)
    .attr("x2", W - PAD).attr("y2", AXIS_Y)
    .attr("stroke", "#9ca3af").attr("stroke-width", 2);

  // Arrow heads
  svg.append("polygon")
    .attr("points", `${W - PAD},${AXIS_Y} ${W - PAD - 8},${AXIS_Y - 4} ${W - PAD - 8},${AXIS_Y + 4}`)
    .attr("fill", "#9ca3af");
  svg.append("polygon")
    .attr("points", `${PAD},${AXIS_Y} ${PAD + 8},${AXIS_Y - 4} ${PAD + 8},${AXIS_Y + 4}`)
    .attr("fill", "#9ca3af");

  // Tick marks and labels for integers in domain
  for (let v = domainMin; v &lt;= domainMax; v += 5) {
    const x = scale(v);
    svg.append("line")
      .attr("x1", x).attr("y1", AXIS_Y - TICK_H / 2)
      .attr("x2", x).attr("y2", AXIS_Y + TICK_H / 2)
      .attr("stroke", "#9ca3af").attr("stroke-width", 1.5);
    svg.append("text")
      .attr("x", x).attr("y", AXIS_Y + 22)
      .attr("text-anchor", "middle")
      .attr("font-size", "11px").attr("fill", "#6b7280")
      .text(v);
  }

  // Shaded region
  const bx = scale(boundary);
  const shadeColor = "#0d9488";
  if (shadedLeft) {
    svg.append("rect")
      .attr("x", PAD).attr("y", AXIS_Y - 6)
      .attr("width", Math.max(0, bx - PAD)).attr("height", 12)
      .attr("fill", shadeColor).attr("opacity", 0.25);
    // Arrow showing infinite extent to the left
    svg.append("polygon")
      .attr("points", `${PAD},${AXIS_Y} ${PAD + 8},${AXIS_Y - 4} ${PAD + 8},${AXIS_Y + 4}`)
      .attr("fill", shadeColor).attr("opacity", 0.6);
  } else {
    svg.append("rect")
      .attr("x", bx).attr("y", AXIS_Y - 6)
      .attr("width", Math.max(0, W - PAD - bx)).attr("height", 12)
      .attr("fill", shadeColor).attr("opacity", 0.25);
    // Arrow showing infinite extent to the right
    svg.append("polygon")
      .attr("points", `${W - PAD},${AXIS_Y} ${W - PAD - 8},${AXIS_Y - 4} ${W - PAD - 8},${AXIS_Y + 4}`)
      .attr("fill", shadeColor).attr("opacity", 0.6);
  }

  // Boundary circle
  if (inclusive) {
    svg.append("circle")
      .attr("cx", bx).attr("cy", AXIS_Y)
      .attr("r", 7).attr("fill", shadeColor).attr("stroke", shadeColor).attr("stroke-width", 2);
  } else {
    svg.append("circle")
      .attr("cx", bx).attr("cy", AXIS_Y)
      .attr("r", 7).attr("fill", "#fff").attr("stroke", shadeColor).attr("stroke-width", 2.5);
  }

  // Boundary label
  svg.append("text")
    .attr("x", bx).attr("y", AXIS_Y - 18)
    .attr("text-anchor", "middle")
    .attr("font-size", "12px").attr("fill", shadeColor).attr("font-weight", "600")
    .text(boundary % 1 === 0 ? boundary : boundary.toFixed(1));

  // Inequality statement
  const circleDesc = inclusive ? "closed circle (boundary included)" : "open circle (boundary excluded)";
  svg.append("text")
    .attr("x", W / 2).attr("y", H - 6)
    .attr("text-anchor", "middle")
    .attr("font-size", "11px").attr("fill", "#6b7280")
    .text(`x ${sym} ${boundary % 1 === 0 ? boundary : boundary.toFixed(1)}   —   ${circleDesc}`);

  return svg.node();
}

12.3 Worked examples
Example 1 — Budgeting. You have $120 to spend on food this month. You’ve already spent $47. You want to buy some items that cost $8 each. How many can you buy without going over budget?
Let \(n\) = number of items.
\[47 + 8n \leq 120\]
Subtract 47 from both sides:
\[8n \leq 73\]
Divide both sides by 8 (positive — no flip):
\[n \leq 9.125\]
Since \(n\) must be a whole number, the answer is \(n \leq 9\). You can buy at most 9 items.
Check: \(47 + 8 \times 9 = 47 + 72 = 119\). Within budget. And \(47 + 8 \times 10 = 127\). Over. Correct.
This means real-world inequalities often need one more step: interpreting the algebra in whole numbers.

Example 2 — Shelf load. A wall-mounted shelf is rated to hold at most 50 kg. Each box you place on it weighs 8 kg.
How many boxes can the shelf safely hold?
The shelf load rating tells you how much weight the shelf can carry on top of it. The brackets that mount the shelf to the wall bear their own weight separately — they don’t count against the shelf’s carrying capacity.
Let \(b\) = number of boxes.
\[8b \leq 50\]
\[b \leq 6.25\]
Since \(b\) must be a whole number: at most 6 boxes.
Check: \(8 \times 6 = 48 \leq 50\). ✓ Seven boxes: \(8 \times 7 = 56 &gt; 50\). ✗
This means safety limits are naturally written as inequalities.

Example 3 — Password validation. A website requires passwords to be at least 8 characters long but no longer than 20 characters. A user types a password. The code checks whether its length \(n\) is acceptable.
The valid range is:
\[8 \leq n \leq 20\]
Any value of \(n\) satisfying both conditions is acceptable. \(n = 7\)? Too short. \(n = 8\)? Fine — the lower boundary is included. \(n = 20\)? Fine. \(n = 21\)? Too long.
This is a compound inequality. In code, you’d check both conditions at once: 8 &lt;= n && n &lt;= 20 (or the equivalent in whatever language you’re using). The mathematics and the code are the same structure.
This means inequalities are a direct way to describe allowed ranges.

Example 4 — An inequality with a negative coefficient. The temperature in a storage room must be kept strictly below \(5°\text{C}\). The thermostat setting \(t\) (in °C) satisfies:
\[-2t + 14 &gt; 4\]
Subtract 14 from both sides:
\[-2t &gt; -10\]
Divide by \(-2\) — negative, so flip:
\[t &lt; 5\]
The thermostat must be set below 5°C. The sign flip was necessary here: if you forgot it and wrote \(t &gt; 5\), you’d be saying temperatures above 5°C are acceptable, which is exactly wrong.
This means the sign-flip rule is not a small detail. It changes the meaning of the answer completely.
