  terms.forEach(t =&gt; {
    svg.append("text")
      .attr("x", xScale(t.n)).attr("y", PAD_T + plotH + 18)
      .attr("text-anchor", "middle").attr("font-size", "11px").attr("fill", "#6b7280")
      .text(t.n);
  });
  svg.append("text")
    .attr("x", PAD_L + plotW / 2).attr("y", H - 6)
    .attr("text-anchor", "middle").attr("font-size", "12px").attr("fill", "#6b7280")
    .text("Position (n)");

  // y-axis label
  svg.append("text")
    .attr("transform", `translate(14, ${PAD_T + plotH / 2}) rotate(-90)`)
    .attr("text-anchor", "middle").attr("font-size", "12px").attr("fill", "#6b7280")
    .text("Value (aₙ)");

  // Line connecting dots
  const lineGen = d3local.line().x(t =&gt; xScale(t.n)).y(t =&gt; yScale(t.v));
  svg.append("path")
    .datum(terms)
