    .attr("font-size", "13px").attr("fill", "#374151")
    .text(`cos(${deg}°) = adj/hyp`);
  svg.append("text").attr("x", px).attr("y", py + 84)
    .attr("font-size", "13px").attr("fill", "#059669")
    .text(`= ${Math.cos(rad).toFixed(4)}`);

  svg.append("text").attr("x", px).attr("y", py + 106)
    .attr("font-size", "13px").attr("fill", "#374151")
    .text(`tan(${deg}°) = opp/adj`);
  svg.append("text").attr("x", px).attr("y", py + 124)
