  const W = svgW - margin.left - margin.right;
  const H = svgH - margin.top - margin.bottom;

  const xMin = -6, xMax = 6;
  const xs = d3.range(xMin, xMax + 0.05, 0.05);
  const ys = xs.map(x =&gt; a * x * x + b * x + c);
  const yMin = Math.min(...ys, -10), yMax = Math.max(...ys, 10);

  const xScale = d3.scaleLinear([xMin, xMax], [0, W]);
  const yScale = d3.scaleLinear([yMin, yMax], [H, 0]);

  const disc = b * b - 4 * a * c;

  // Roots
  let roots = [];
  if (disc &gt; 0) {
    roots = [
      (-b + Math.sqrt(disc)) / (2 * a),
      (-b - Math.sqrt(disc)) / (2 * a)
    ].filter(r =&gt; r &gt;= xMin && r &lt;= xMax);
  } else if (Math.abs(disc) &lt; 1e-9) {
    const r = -b / (2 * a);
    if (r &gt;= xMin && r &lt;= xMax) roots = [r];
  }

  // Vertex
  const vx = -b / (2 * a);
  const vy = a * vx * vx + b * vx + c;

  const svg = d3.create("svg")
    .attr("width", svgW).attr("height", svgH)
    .style("font-family", "inherit");

  const g = svg.append("g")
    .attr("transform", `translate(${margin.left},${margin.top})`);

  // Axes
  if (yScale(0) &gt;= 0 && yScale(0) &lt;= H) {
    g.append("line")
      .attr("x1", 0).attr("y1", yScale(0))
      .attr("x2", W).attr("y2", yScale(0))
      .attr("stroke", "#9ca3af").attr("stroke-width", 1);
  }
  if (xScale(0) &gt;= 0 && xScale(0) &lt;= W) {
    g.append("line")
      .attr("x1", xScale(0)).attr("y1", 0)
      .attr("x2", xScale(0)).attr("y2", H)
      .attr("stroke", "#9ca3af").attr("stroke-width", 1);
  }

  // Grid lines
  for (let xi = xMin; xi &lt;= xMax; xi++) {
    g.append("line")
      .attr("x1", xScale(xi)).attr("y1", 0)
      .attr("x2", xScale(xi)).attr("y2", H)
      .attr("stroke", "#f3f4f6").attr("stroke-width", 1);
    g.append("text")
      .attr("x", xScale(xi)).attr("y", yScale(0) + 14)
      .attr("text-anchor", "middle").attr("font-size", "11px").attr("fill", "#9ca3af")
      .text(xi === 0 ? "" : xi);
  }

  // Curve
  const line = d3.line()
    .x(x =&gt; xScale(x))
    .y(x =&gt; yScale(a * x * x + b * x + c))
    .curve(d3.curveCatmullRom);

  g.append("path")
    .datum(xs)
    .attr("d", line)
    .attr("fill", "none")
    .attr("stroke", "#2563eb")
    .attr("stroke-width", 2.5);

  // Roots
  roots.forEach(r =&gt; {
    g.append("circle")
      .attr("cx", xScale(r)).attr("cy", yScale(0))
      .attr("r", 5)
      .attr("fill", "#dc2626").attr("stroke", "#fff").attr("stroke-width", 1.5);
  });

  // Vertex
  if (vx &gt;= xMin && vx &lt;= xMax) {
    g.append("circle")
      .attr("cx", xScale(vx)).attr("cy", yScale(vy))
      .attr("r", 6)
      .attr("fill", "#f59e0b").attr("stroke", "#fff").attr("stroke-width", 1.5);
  }

  // "No real roots" label
  if (disc &lt; 0) {
    g.append("text")
      .attr("x", W / 2).attr("y", H / 2)
      .attr("text-anchor", "middle").attr("font-size", "13px").attr("fill", "#dc2626")
      .text("no real roots (Δ &lt; 0)");
  }

  // Info panel at top
  const eqStr = `y = ${a}x² ${b &gt;= 0 ? "+" : ""}${b}x ${c &gt;= 0 ? "+" : ""}${c}`;
  svg.append("text")
    .attr("x", margin.left).attr("y", 22)
    .attr("font-size", "13px").attr("font-weight", "600").attr("fill", "#111827")
    .text(eqStr);

  svg.append("text")
    .attr("x", margin.left + 220).attr("y", 22)
    .attr("font-size", "13px").attr("fill", disc &gt;= 0 ? "#059669" : "#dc2626")
    .text(`Δ = ${disc.toFixed(2)}  (${disc &gt; 0 ? "2 roots" : disc === 0 ? "1 root" : "no real roots"})`);

  // Vertex label
  if (vx &gt;= xMin && vx &lt;= xMax) {
    svg.append("text")
      .attr("x", margin.left + xScale(vx) + 8)
      .attr("y", margin.top + yScale(vy) - 4)
      .attr("font-size", "11px").attr("fill", "#d97706")
      .text(`vertex (${vx.toFixed(2)}, ${vy.toFixed(2)})`);
  }

  return svg.node();
}

18.4 Worked examples
Example 1 (sci) — height of a thrown ball
A ball is thrown upward from ground level with an initial speed of 14 m/s. Ignoring air resistance, its height in metres after \(t\) seconds is:
\[h(t) = 14t - 4.9t^2\]
When does it land?
Landing means \(h = 0\):
\[14t - 4.9t^2 = 0\]
Factor out a common term of \(t\):
\[t(14 - 4.9t) = 0\]
Either \(t = 0\) (the moment it’s thrown) or \(14 - 4.9t = 0\). Solving the second:
\[4.9t = 14 \implies t = \frac{14}{4.9} \approx 2.86 \text{ s}\]
The ball lands after about 2.86 seconds.
The vertex — the highest point — is at \(t = 14/(2 \times 4.9) = 14/9.8
\approx 1.43\) s, at height \(h(1.43) = 14(1.43) - 4.9(1.43)^2 \approx
20.02 - 10.02 \approx 10\) m.
This means one quadratic can answer several different questions about the same motion.


