  ];

  params.forEach(p =&gt; {
    const wrap = document.createElement("div");
    const lbl = document.createElement("label");
    lbl.style.cssText = "font-size:0.8rem; color:#374151; display:block;";
    const span = document.createElement("span"); span.textContent = p.val;
    lbl.appendChild(document.createTextNode(p.label + " = ")); lbl.appendChild(span);
    const input = document.createElement("input");
    input.type = "range"; input.min = p.min; input.max = p.max; input.step = p.step; input.value = p.val;
    input.style.width = "100%";
    wrap.appendChild(lbl); wrap.appendChild(input);
    controls.appendChild(wrap);
    p.input = input;
    p.span = span;
  });

  const infoEl = document.createElement("div");
  infoEl.style.cssText = "font-size:0.88rem; margin-bottom:0.5rem; min-height:1.4em; font-weight:600;";

  const canvas = document.createElement("canvas");
  canvas.width = 400; canvas.height = 400;
  canvas.style.cssText = "border:1px solid #e5e7eb; border-radius:6px; display:block; max-width:400px;";

  div.appendChild(controls); div.appendChild(infoEl); div.appendChild(canvas);

  function draw() {
    const vals = {};
    params.forEach(p =&gt; {
      const v = parseFloat(p.input.value);
      p.span.textContent = v;
      vals[p.id] = v;
    });

    const {sa1:a1, sb1:b1, sc1:c1, sa2:a2, sb2:b2, sc2:c2} = vals;
    const det = a1*b2 - a2*b1;

    const ctx = canvas.getContext("2d");
    const W = canvas.width, H = canvas.height;
    ctx.clearRect(0, 0, W, H);
    const range = 12;
    function px(x) { return (x+range)/(2*range)*W; }
    function py(y) { return H-(y+range)/(2*range)*H; }

    // Grid
    ctx.strokeStyle = "#f3f4f6"; ctx.lineWidth = 1;
    for (let i = -10; i &lt;= 10; i += 2) {
      ctx.beginPath(); ctx.moveTo(px(i), 0); ctx.lineTo(px(i), H); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(0, py(i)); ctx.lineTo(W, py(i)); ctx.stroke();
    }
    ctx.strokeStyle = "#9ca3af"; ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(0, py(0)); ctx.lineTo(W, py(0)); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(px(0), 0); ctx.lineTo(px(0), H); ctx.stroke();

    // Line 1: a1*x + b1*y = c1  =&gt; y = (c1 - a1*x)/b1
    function drawLine(a, b, c, color) {
      ctx.strokeStyle = color; ctx.lineWidth = 2.5;
      ctx.beginPath();
      let first = true;
      for (let xi = 0; xi &lt;= W; xi++) {
        const x = -range + (xi / W) * 2 * range;
        let y;
        if (Math.abs(b) &gt; 0.001) y = (c - a*x) / b;
        else { if (xi === 0) { ctx.moveTo(px(c/a), 0); ctx.lineTo(px(c/a), H); ctx.stroke(); } return; }
        if (first) { ctx.moveTo(xi, py(y)); first = false; }
        else ctx.lineTo(xi, py(y));
      }
      ctx.stroke();
    }

    drawLine(a1, b1, c1, "#2563eb");
    drawLine(a2, b2, c2, "#ef4444");

    if (Math.abs(det) &lt; 0.001) {
      const parallel = Math.abs(a1*c2 - a2*c1) &gt; 0.001 || Math.abs(b1*c2 - b2*c1) &gt; 0.001;
      infoEl.textContent = parallel ? "No unique solution — lines are parallel" : "Infinitely many solutions — same line";
      infoEl.style.color = "#dc2626";
    } else {
      const x = (c1*b2 - c2*b1) / det;
      const y = (a1*c2 - a2*c1) / det;
      ctx.fillStyle = "#7c3aed";
      ctx.beginPath(); ctx.arc(px(x), py(y), 6, 0, 2*Math.PI); ctx.fill();
      ctx.fillStyle = "#374151"; ctx.font = "bold 12px sans-serif";
      ctx.fillText("(" + x.toFixed(2) + ", " + y.toFixed(2) + ")", px(x)+8, py(y)-8);
      infoEl.textContent = "Solution: x = " + x.toFixed(2) + ", y = " + y.toFixed(2);
      infoEl.style.color = "#7c3aed";
    }

    // Equation labels
    ctx.font = "12px sans-serif";
    ctx.fillStyle = "#2563eb";
    ctx.fillText(a1+"x + "+b1+"y = "+c1, 8, 16);
    ctx.fillStyle = "#ef4444";
    ctx.fillText(a2+"x + "+b2+"y = "+c2, 8, 32);
  }

  params.forEach(p =&gt; p.input.addEventListener("input", draw));
  draw();
  return div;
}









23.2.2 Method 2 — Substitution
Solve one equation for one variable, then substitute into the other. This eliminates one unknown and leaves a single equation you can solve directly.
\[\begin{cases} x + y = 5 \qquad (1) \\ x - y = 1 \qquad (2) \end{cases}\]
From equation (1): \(x = 5 - y\).
Substitute into equation (2):
\[(5 - y) - y = 1\]
\[5 - 2y = 1\]
\[-2y = -4 \implies y = 2\]
Now substitute \(y = 2\) back into \(x = 5 - y\):
\[x = 5 - 2 = 3\]
Solution: \(x = 3\), \(y = 2\). This means substitution temporarily turns a two-variable problem back into the one-variable algebra you already know.
When to use it: substitution works cleanly when one equation already has a variable with coefficient 1 (so there’s no fraction to deal with when you isolate it).


23.2.3 Method 3 — Elimination
Multiply one or both equations by constants to make the coefficient of one variable the same (or opposite) in both equations. Then add or subtract to eliminate that variable.
\[\begin{cases} 2x + 3y = 12 \qquad (1) \\ 4x - y = \phantom{1}5 \qquad\;\; (2) \end{cases}\]
The coefficient of \(y\) is \(3\) in equation (1) and \(-1\) in equation (2). Multiply equation (2) by \(3\) to make the \(y\)-coefficients match in magnitude:
\[3 \times (2): \quad 12x - 3y = 15 \qquad (2')\]
Now add equations (1) and (2’):
\[(2x + 3y) + (12x - 3y) = 12 + 15\]
\[14x = 27 \implies x = \frac{27}{14}\]
Substitute into equation (1):
\[2 \cdot \frac{27}{14} + 3y = 12 \implies \frac{27}{7} + 3y = 12 \implies 3y = 12 - \frac{27}{7} = \frac{57}{7} \implies y = \frac{19}{7}\]
Check in equation (2): \(4 \cdot \frac{27}{14} - \frac{19}{7} = \frac{54}{7} - \frac{19}{7} = \frac{35}{7} = 5\) ✓ This means elimination works by combining the equations until one variable disappears.
When to use it: elimination is best when no variable has a coefficient of 1, or when the numbers make substitution awkward. It’s also the method that generalises directly to 3×3 and larger systems (Gaussian elimination).

23.4 Worked examples

Example 1 — Business: supply and demand equilibrium.
A market for concert tickets has a supply curve and a demand curve:
\[\begin{cases} p = 2q + 10 \qquad \text{(supply: price rises with quantity)} \\ p = -3q + 60 \qquad \text{(demand: price falls as quantity rises)} \end{cases}\]
Here \(p\) = price (dollars), \(q\) = quantity (thousands of tickets). The equilibrium is where supply price equals demand price.
Set the right-hand sides equal (substitution):
\[2q + 10 = -3q + 60\]
\[5q = 50 \implies q = 10\]
\[p = 2(10) + 10 = 30\]
Equilibrium: 10,000 tickets at $30 each.
Check in the demand equation: \(-3(10) + 60 = -30 + 60 = 30\) ✓
The determinant check: rewrite as \(\begin{cases} 2q - p = -10 \\ -3q - p = -60 \end{cases}\). Matrix \(\begin{pmatrix} 2 & -1 \\ -3 & -1 \end{pmatrix}\), \(\det = (2)(-1) - (-1)(-3) = -2 - 3 = -5 \neq 0\). Unique solution confirmed. This means equilibrium is simply the point where two different rules predict the same price and quantity.


