      g.append("circle").attr("cx", xS(2)).attr("cy", yS(4)).attr("r", 5).attr("fill","white").attr("stroke","#2563eb").attr("stroke-width",2);
    }

    if (p.id === "Jump") {
      const xS = d3_cont.scaleLinear().domain([0, 5]).range([0, iW]);
      const yS = d3_cont.scaleLinear().domain([0, 7]).range([iH, 0]);
      g.append("g").attr("transform", `translate(0,${iH})`).call(d3_cont.axisBottom(xS).ticks(5).tickSize(3));
      g.append("g").call(d3_cont.axisLeft(yS).ticks(5).tickSize(3));
      const line = d3_cont.line().x(d =&gt; xS(d[0])).y(d =&gt; yS(d[1]));
      // y=x for x&lt;3
      g.append("path").datum([[0,0],[2.97,2.97]]).attr("d", line).attr("fill","none").attr("stroke","#2563eb").attr("stroke-width",2);
      // y=2x-4 for x&gt;3
      g.append("path").datum([[3.03,2.06],[5,6]]).attr("d", line).attr("fill","none").attr("stroke","#2563eb").attr("stroke-width",2);
      // open circles at gap ends
      g.append("circle").attr("cx", xS(3)).attr("cy", yS(3)).attr("r", 4).attr("fill","white").attr("stroke","#2563eb").attr("stroke-width",2);
      g.append("circle").attr("cx", xS(3)).attr("cy", yS(2)).attr("r", 4).attr("fill","white").attr("stroke","#2563eb").attr("stroke-width",2);
    }

    if (p.id === "Infinite") {
      const xS = d3_cont.scaleLinear().domain([-2, 2]).range([0, iW]);
      const yS = d3_cont.scaleLinear().domain([-4, 4]).range([iH, 0]);
      g.append("g").attr("transform", `translate(0,${iH/2})`).call(d3_cont.axisBottom(xS).ticks(4).tickSize(3));
      g.append("g").call(d3_cont.axisLeft(yS).ticks(4).tickSize(3));
      // 1/x left branch
      const leftB = d3_cont.range(-2, -0.28, 0.05).map(x =&gt; [x, 1/x]);
      const rightB = d3_cont.range(0.28, 2.01, 0.05).map(x =&gt; [x, 1/x]);
      const line = d3_cont.line().x(d =&gt; xS(d[0])).y(d =&gt; yS(d[1])).defined(d =&gt; Math.abs(d[1]) &lt;= 4);
      g.append("path").datum(leftB).attr("d", line).attr("fill","none").attr("stroke","#2563eb").attr("stroke-width",2);
      g.append("path").datum(rightB).attr("d", line).attr("fill","none").attr("stroke","#2563eb").attr("stroke-width",2);
      // vertical dashed asymptote
      g.append("line")
        .attr("x1", xS(0)).attr("x2", xS(0))
        .attr("y1", 0).attr("y2", iH)
        .attr("stroke", "#dc2626").attr("stroke-width", 1.5)
        .attr("stroke-dasharray", "4,3");
    }

    wrap.appendChild(svg.node());
    svgRow.appendChild(wrap);
  });

  container.appendChild(svgRow);

  // Condition analysis
  const info = document.createElement("div");
  info.style.cssText = "margin-top:1rem; border:1px solid #e5e7eb; border-radius:8px; padding:0.75rem 1rem; background:#fff;";

  const title = document.createElement("div");
  title.style.cssText = "font-weight:600; font-size:0.95em; color:#374151; margin-bottom:0.5rem;";
  title.textContent = `${selectedPanel} discontinuity — condition analysis`;
  info.appendChild(title);

  conditions[selectedPanel].forEach(c =&gt; {
    const row = document.createElement("div");
    row.style.cssText = "display:flex; align-items:baseline; gap:0.5rem; padding:0.2rem 0; font-size:0.9em;";
    const icon = document.createElement("span");
    icon.textContent = c.pass ? "✓" : "✗";
    icon.style.cssText = `font-weight:700; color:${c.pass ? "#059669" : "#dc2626"}; min-width:1.2em;`;
    const text = document.createElement("span");
    text.style.color = "#374151";
    text.textContent = c.label + " — " + c.note;
    row.appendChild(icon);
    row.appendChild(text);
    info.appendChild(row);
  });

  container.appendChild(info);
  return container;
}

