    counter.textContent = current === 0 ? "Click to reveal steps" : `Step ${current} of ${totalSteps}`;
  }

  nextBtn.onclick = () =&gt; { if (current &lt; totalSteps) { current++; renderSteps(); updateButtons(); } };
