    color:#6b7280;
    border:1px solid #d1d5db;
    border-radius:5px;
    cursor:pointer;
    font-size:0.88rem;
  `;

  const counter = document.createElement("span");
  counter.style.cssText = "font-size:0.82rem;color:#9ca3af;margin-left:0.25rem;";
  counter.textContent = `0 / ${steps.length}`;

  function update() {
    stepEls.forEach((el, i) =&gt; {
      el.style.display = i &lt;= current ? "block" : "none";
    });
    counter.textContent = `${current + 1} / ${steps.length}`;
    nextBtn.disabled = current &gt;= steps.length - 1;
    nextBtn.style.opacity = nextBtn.disabled ? "0.45" : "1";
  }

  nextBtn.addEventListener("click", () =&gt; {
    if (current &lt; steps.length - 1) { current++; update(); }
  });
  resetBtn.addEventListener("click", () =&gt; {
    current = -1; update();
  });

  btnRow.appendChild(nextBtn);
  btnRow.appendChild(resetBtn);
  btnRow.appendChild(counter);

  const wrapper = document.createElement("div");
  wrapper.style.cssText = `
    border:1px solid #e5e7eb;
    border-radius:8px;
    padding:1rem 1.1rem;
    max-width:560px;
    font-family:sans-serif;
    margin-top:0.75rem;
  `;
  wrapper.appendChild(problemDiv);
  wrapper.appendChild(stepsContainer);
  wrapper.appendChild(btnRow);

  update();
  return wrapper;
}
















