    presetBar.appendChild(btn);
  });

  // Box-Muller bivariate normal with correlation rho
  function bivariateNormal(n, rho, seed) {
    // Simple LCG for reproducible-ish noise
    let s = seed || 42;
    function rand() { s = (s * 1664525 + 1013904223) & 0xffffffff; return (s &gt;&gt;&gt; 0) / 0x100000000; }
    function stdNormal() {
      const u1 = rand() || 1e-10, u2 = rand();
      return Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
    }
    const pts = [];
    for (let i = 0; i &lt; n; i++) {
      const z1 = stdNormal(), z2 = stdNormal();
      pts.push({ x: z1, y: rho * z1 + Math.sqrt(1 - rho * rho) * z2 });
    }
    return pts;
  }

  function computeR(pts) {
    const n = pts.length;
    if (n &lt; 2) return NaN;
    const mx = pts.reduce((a, p) =&gt; a + p.x, 0) / n;
    const my = pts.reduce((a, p) =&gt; a + p.y, 0) / n;
    let num = 0, dx2 = 0, dy2 = 0;
    pts.forEach(p =&gt; {
      const dx = p.x - mx, dy = p.y - my;
      num += dx * dy; dx2 += dx * dx; dy2 += dy * dy;
    });
    const denom = Math.sqrt(dx2 * dy2);
    return denom &lt; 1e-12 ? 0 : num / denom;
  }

