34.6 6 · Linear regression
Once you have established (from a scatter plot) that two variables have a linear form, you can model that relationship with a line. That line lets you do two things the correlation coefficient cannot: make predictions for new values, and quantify how much \(y\) changes per unit of \(x\).
The problem. Suppose you have a scatter of points that approximately follow a line. Which line? You could draw many lines that pass “through” the cloud. The least-squares line is the one that minimises the sum of squared residuals — where a residual \(e_i = y_i - \hat{y}_i\) is the vertical distance from each point to the line.
Why squared? Squaring makes all residuals positive (so positive and negative errors don’t cancel), and it penalises large errors more heavily than small ones. The least-squares line is the unique line that minimises the total squared error — it is “as close as possible” to all the points simultaneously. This means regression is not guessing a line by eye; it is choosing the line that makes overall prediction error as small as possible by a precise rule.
The formulas. For the least-squares line \(\hat{y} = b_0 + b_1 x\):
\[b_1 = r \cdot \frac{s_y}{s_x}\]
\[b_0 = \bar{y} - b_1 \bar{x}\]
where \(r\) is the Pearson correlation, \(s_x\) and \(s_y\) are the standard deviations of \(x\) and \(y\), and \(\bar{x}\), \(\bar{y}\) are the means. This means the slope depends on two things at once: how strongly the variables move together, and how their units and spreads compare.
Interpretation.
\(b_1\) (slope): for every one-unit increase in \(x\), the predicted value of \(y\) changes by \(b_1\) units. Always interpret this in context — the units matter.
\(b_0\) (intercept): the predicted value of \(y\) when \(x = 0\). This is sometimes meaningful (it might represent a baseline), but often extrapolating to \(x = 0\) is outside the range of the data and the intercept is just an algebraic anchor with no practical interpretation.
The regression line always passes through \((\bar{x}, \bar{y})\). This is a useful sanity check. This means the fitted line is anchored at the centre of the data cloud, not floating independently of the observed averages.


Code
{
  const W = 500, H = 340, PAD = 45;
  const MAX_PTS = 20;

  let points = [];
  let showResiduals = false;

  const svg = d3.create("svg")
    .attr("width", W).attr("height", H)
    .style("border", "1px solid #e5e7eb").style("border-radius", "6px")
    .style("background", "#fafafa").style("cursor", "crosshair");

  const xScale = d3.scaleLinear().domain([0, 10]).range([PAD, W - PAD]);
  const yScale = d3.scaleLinear().domain([0, 10]).range([H - PAD, PAD]);

  // Grid lines
  const grid = svg.append("g").attr("opacity", 0.25);
  xScale.ticks(5).forEach(t =&gt; grid.append("line").attr("x1", xScale(t)).attr("x2", xScale(t)).attr("y1", PAD).attr("y2", H - PAD).attr("stroke","#9ca3af").attr("stroke-dasharray","3,3"));
  yScale.ticks(5).forEach(t =&gt; grid.append("line").attr("x1", PAD).attr("x2", W - PAD).attr("y1", yScale(t)).attr("y2", yScale(t)).attr("stroke","#9ca3af").attr("stroke-dasharray","3,3"));

  svg.append("g").attr("transform", `translate(0,${H - PAD})`).call(d3.axisBottom(xScale).ticks(5)).attr("color","#9ca3af");
  svg.append("g").attr("transform", `translate(${PAD},0)`).call(d3.axisLeft(yScale).ticks(5)).attr("color","#9ca3af");
  svg.append("text").attr("x", W/2).attr("y", H - 5).attr("text-anchor","middle").attr("fill","#6b7280").attr("font-size","12px").text("x");
  svg.append("text").attr("transform","rotate(-90)").attr("x", -H/2).attr("y", 14).attr("text-anchor","middle").attr("fill","#6b7280").attr("font-size","12px").text("y");

  const hintText = svg.append("text").attr("x", W/2).attr("y", H/2)
    .attr("text-anchor","middle").attr("fill","#9ca3af").attr("font-size","13px")
    .text("Click anywhere to add a data point");

  const residGroup = svg.append("g");
  const lineGroup = svg.append("g");
  const dotsGroup = svg.append("g");

  function leastSquares(pts) {
    const n = pts.length;
    if (n &lt; 2) return null;
    const mx = pts.reduce((a, p) =&gt; a + p.x, 0) / n;
    const my = pts.reduce((a, p) =&gt; a + p.y, 0) / n;
    let num = 0, den = 0;
    pts.forEach(p =&gt; { const dx = p.x - mx; num += dx * (p.y - my); den += dx * dx; });
    if (Math.abs(den) &lt; 1e-12) return null;
    const b1 = num / den;
    const b0 = my - b1 * mx;
    const yhat = pts.map(p =&gt; b0 + b1 * p.x);
    const ssTot = pts.reduce((a, p) =&gt; a + (p.y - my) ** 2, 0);
    const ssRes = pts.reduce((a, p, i) =&gt; a + (p.y - yhat[i]) ** 2, 0);
    const r2 = ssTot &lt; 1e-12 ? 1 : 1 - ssRes / ssTot;
    return { b0, b1, r2, yhat };
  }

  function render() {
    hintText.style("display", points.length === 0 ? null : "none");

    const fit = leastSquares(points);

    // Residual lines
    residGroup.selectAll("line").data(showResiduals && fit ? points : [])
      .join("line")
      .attr("x1", d =&gt; xScale(d.x)).attr("x2", d =&gt; xScale(d.x))
      .attr("y1", d =&gt; yScale(d.y))
      .attr("y2", (d, i) =&gt; yScale(fit.yhat[i]))
      .attr("stroke", "#ef4444").attr("stroke-width", 1.5).attr("opacity", 0.7);

    // Regression line
    if (fit) {
      const x0 = 0, x1 = 10;
      lineGroup.selectAll("line").data([1]).join("line")
        .attr("x1", xScale(x0)).attr("x2", xScale(x1))
        .attr("y1", yScale(fit.b0 + fit.b1 * x0))
        .attr("y2", yScale(fit.b0 + fit.b1 * x1))
        .attr("stroke", "#1d4ed8").attr("stroke-width", 2).attr("opacity", 0.85);
    } else {
      lineGroup.selectAll("line").remove();
    }

    // Dots
    dotsGroup.selectAll("circle").data(points).join("circle")
      .attr("cx", d =&gt; xScale(d.x)).attr("cy", d =&gt; yScale(d.y))
      .attr("r", 5).attr("fill", "#3b82f6").attr("stroke", "#1d4ed8").attr("stroke-width", 1).attr("opacity", 0.8);

    // Stats display
    if (fit) {
      statsDiv.innerHTML = `
        &lt;span style="margin-right:1.5rem;"&gt;&lt;em&gt;b&lt;/em&gt;&lt;sub&gt;0&lt;/sub&gt; = &lt;strong&gt;${fit.b0.toFixed(3)}&lt;/strong&gt;&lt;/span&gt;
        &lt;span style="margin-right:1.5rem;"&gt;&lt;em&gt;b&lt;/em&gt;&lt;sub&gt;1&lt;/sub&gt; = &lt;strong&gt;${fit.b1.toFixed(3)}&lt;/strong&gt;&lt;/span&gt;
        &lt;span&gt;&lt;em&gt;R&lt;/em&gt;&lt;sup&gt;2&lt;/sup&gt; = &lt;strong&gt;${fit.r2.toFixed(3)}&lt;/strong&gt;&lt;/span&gt;
        &lt;span style="margin-left:1rem; color:#6b7280; font-size:0.85em;"&gt;(${points.length} point${points.length===1?"":"s"})&lt;/span&gt;`;
      statsDiv.style.color = "#1e3a8a";
    } else {
      statsDiv.textContent = points.length &lt; 2 ? "Add at least 2 points to fit a line." : "";
      statsDiv.style.color = "#6b7280";
    }
  }

  svg.on("click", function(event) {
    if (points.length &gt;= MAX_PTS) return;
    const [px, py] = d3.pointer(event);
    const x = xScale.invert(px), y = yScale.invert(py);
    if (x &lt; 0 || x &gt; 10 || y &lt; 0 || y &gt; 10) return;
    points.push({ x, y });
    render();
  });

  // Controls
  const residBtn = document.createElement("button");
  residBtn.textContent = "Show residuals";
  residBtn.style.cssText = "padding:0.3rem 0.8rem; border:1px solid #d1d5db; border-radius:4px; background:#fff; cursor:pointer; font-size:0.875em;";
  residBtn.onclick = () =&gt; {
    showResiduals = !showResiduals;
    residBtn.textContent = showResiduals ? "Hide residuals" : "Show residuals";
    residBtn.style.background = showResiduals ? "#fee2e2" : "#fff";
    render();
  };

  const clearBtn = document.createElement("button");
  clearBtn.textContent = "Clear";
  clearBtn.style.cssText = "padding:0.3rem 0.8rem; border:1px solid #e5e7eb; border-radius:4px; background:#f9fafb; cursor:pointer; font-size:0.875em; color:#6b7280;";
  clearBtn.onclick = () =&gt; { points = []; showResiduals = false; residBtn.textContent = "Show residuals"; residBtn.style.background = "#fff"; render(); };

  const statsDiv = document.createElement("div");
  statsDiv.style.cssText = "min-height:1.6em; font-size:0.95em; text-align:center; margin-top:0.4rem; padding:0.4rem; background:#eff6ff; border-radius:4px;";

  const ctrlRow = document.createElement("div");
  ctrlRow.style.cssText = "display:flex; gap:0.5rem; margin:0.5rem 0;";
  ctrlRow.append(residBtn, clearBtn);

  const hint = document.createElement("p");
  hint.style.cssText = "font-size:0.85em; color:#374151; margin-bottom:0.4rem;";
  hint.textContent = `Click on the plot to add points (up to ${MAX_PTS}). The least-squares line updates in real time.`;

  render();

  const container = document.createElement("div");
  container.style.cssText = "margin:1rem 0; font-family:inherit;";
  container.append(hint, svg.node(), ctrlRow, statsDiv);
  return container;
}

