{
  const d3 = await require("d3@7");

  const width = 560, height = 300;
  const margin = { top: 20, right: 20, bottom: 45, left: 55 };
  const innerW = width - margin.left - margin.right;
  const innerH = height - margin.top - margin.bottom;

  const m = smdM, c = smdC, k = smdK;
  const disc = c * c - 4 * m * k;

  // Classify regime
  const eps = 1e-6;
  let regime;
  if (disc &gt; eps) regime = "Overdamped (Δ &gt; 0)";
  else if (disc &gt; -eps) regime = "Critically damped (Δ = 0)";
  else regime = "Underdamped (Δ &lt; 0)";

  // Euler integration: m x'' + c x' + k x = 0, x(0)=1, x'(0)=0
  const dt = 0.01, steps = 600;
  const ts = [], xs = [];
  let x = 1, v = 0;
  for (let i = 0; i &lt;= steps; i++) {
    ts.push(i * dt);
    xs.push(x);
    const a = (-c * v - k * x) / m;
    v += a * dt;
    x += v * dt;
  }

  const xExtent = d3.extent(xs);
  const yMin = Math.min(xExtent[0], -1.05);
  const yMax = Math.max(xExtent[1], 1.05);

  const xScale = d3.scaleLinear().domain([0, steps * dt]).range([0, innerW]);
  const yScale = d3.scaleLinear().domain([yMin, yMax]).range([innerH, 0]);

  const svg = d3.create("svg")
    .attr("viewBox", `0 0 ${width} ${height}`)
    .attr("width", width)
    .attr("height", height)
    .style("font-family", "sans-serif");

  const g = svg.append("g").attr("transform", `translate(${margin.left},${margin.top})`);

  // Zero line
  g.append("line")
    .attr("x1", 0).attr("x2", innerW)
    .attr("y1", yScale(0)).attr("y2", yScale(0))
    .attr("stroke", "#999").attr("stroke-dasharray", "4,3").attr("stroke-width", 1);

  // Exponential envelope for underdamped
  if (disc &lt; -eps) {
    const alpha = c / (2 * m);
    const envLine = d3.line()
      .x((_, i) =&gt; xScale(ts[i]))
      .y((v) =&gt; yScale(v));

    const envPos = ts.map(t =&gt; Math.exp(-alpha * t));
    const envNeg = ts.map(t =&gt; -Math.exp(-alpha * t));

    g.append("path")
      .datum(envPos)
      .attr("fill", "none")
      .attr("stroke", "#999")
      .attr("stroke-dasharray", "5,4")
      .attr("stroke-width", 1.2)
