  const d3 = await require("d3@7");

  const a11 = ppParams.ppA11;
  const a12 = ppParams.ppA12;
  const a21 = ppParams.ppA21;
  const a22 = ppParams.ppA22;

  // Eigenvalue computation via quadratic formula
  const tr  = a11 + a22;
  const det = a11 * a22 - a12 * a21;
  const disc = tr * tr - 4 * det;

  let lam1, lam2, lamStr1, lamStr2, classification, stableColor;

  if (disc &gt;= 0) {
    // Real eigenvalues
    lam1 = (tr + Math.sqrt(disc)) / 2;
    lam2 = (tr - Math.sqrt(disc)) / 2;
    lamStr1 = lam1.toFixed(3);
    lamStr2 = lam2.toFixed(3);
    if (lam1 * lam2 &lt; 0) {
      classification = "Saddle (unstable)";
      stableColor = "saddle";
    } else if (lam1 &lt; 0 && lam2 &lt; 0) {
      classification = "Stable node";
      stableColor = "stable";
    } else if (lam1 &gt; 0 && lam2 &gt; 0) {
      classification = "Unstable node";
      stableColor = "unstable";
    } else {
      // one or both zero
      classification = "Non-isolated equilibrium";
      stableColor = "neutral";
    }
  } else {
    // Complex eigenvalues: α ± βi
    const alpha = tr / 2;
    const beta  = Math.sqrt(-disc) / 2;
    lam1 = { re: alpha, im:  beta };
    lam2 = { re: alpha, im: -beta };
    const sign = beta &gt;= 0 ? "+" : "-";
    lamStr1 = `${alpha.toFixed(3)} + ${beta.toFixed(3)}i`;
    lamStr2 = `${alpha.toFixed(3)} − ${beta.toFixed(3)}i`;
    if (Math.abs(alpha) &lt; 1e-9) {
      classification = "Centre (neutrally stable)";
      stableColor = "neutral";
    } else if (alpha &lt; 0) {
      classification = "Stable spiral";
      stableColor = "stable";
    } else {
      classification = "Unstable spiral";
      stableColor = "unstable";
    }
  }

  // SVG dimensions
  const W = 560, H = 400;
  const margin = { top: 30, right: 20, bottom: 40, left: 40 };
  const iW = W - margin.left - margin.right;
  const iH = H - margin.top  - margin.bottom;

  const xDom = [-3, 3], yDom = [-3, 3];
  const xSc = d3.scaleLinear().domain(xDom).range([0, iW]);
  const ySc = d3.scaleLinear().domain(yDom).range([iH, 0]);

  const svg = d3.create("svg")
    .attr("width", W).attr("height", H)
    .style("font-family", "sans-serif");

  const g = svg.append("g")
    .attr("transform", `translate(${margin.left},${margin.top})`);

  // Background
  g.append("rect")
    .attr("width", iW).attr("height", iH)
    .attr("fill", "#fafafa").attr("stroke", "#ccc");

  // Axes
  g.append("line")
    .attr("x1", xSc(0)).attr("x2", xSc(0))
    .attr("y1", 0).attr("y2", iH)
    .attr("stroke", "#aaa").attr("stroke-width", 1);
  g.append("line")
    .attr("x1", 0).attr("x2", iW)
    .attr("y1", ySc(0)).attr("y2", ySc(0))
    .attr("stroke", "#aaa").attr("stroke-width", 1);

  // Axis labels
  g.append("text").attr("x", iW + 5).attr("y", ySc(0) + 4).text("x₁").attr("font-size", 11).attr("fill", "#555");
  g.append("text").attr("x", xSc(0) + 4).attr("y", -8).text("x₂").attr("font-size", 11).attr("fill", "#555");

  // Direction field: 15×15 grid
  const gridN = 15;
  const arrowLen = (iW / gridN) * 0.38;
  for (let i = 0; i &lt;= gridN; i++) {
    for (let j = 0; j &lt;= gridN; j++) {
      const x = xDom[0] + (i / gridN) * (xDom[1] - xDom[0]);
      const y = yDom[0] + (j / gridN) * (yDom[1] - yDom[0]);
      const dx = a11 * x + a12 * y;
      const dy = a21 * x + a22 * y;
      const mag = Math.sqrt(dx * dx + dy * dy) || 1;
      const nx = dx / mag, ny = dy / mag;
      const cx = xSc(x), cy = ySc(y);
      const ex = cx + nx * arrowLen;
      const ey = cy - ny * arrowLen;
      g.append("line")
        .attr("x1", cx - nx * arrowLen * 0.5)
        .attr("y1", cy + ny * arrowLen * 0.5)
        .attr("x2", ex)
        .attr("y2", ey)
        .attr("stroke", "#bbb").attr("stroke-width", 0.8)
        .attr("marker-end", "url(#arrowhead)");
    }
  }

  // Arrowhead marker
  svg.append("defs").append("marker")
    .attr("id", "arrowhead")
    .attr("viewBox", "0 -3 6 6")
    .attr("refX", 5).attr("refY", 0)
    .attr("markerWidth", 4).attr("markerHeight", 4)
    .attr("orient", "auto")
    .append("path").attr("d", "M0,-3L6,0L0,3").attr("fill", "#bbb");

  // Trajectory colours
  const trajColor = stableColor === "stable"   ? "#1e6fcc" :
                    stableColor === "unstable"  ? "#cc3333" :
                    stableColor === "saddle"    ? null       : "#888";

  // 8 trajectories from radius 2, evenly spaced angles
  const nTraj = 8;
  const r0 = 2;
  const dt = 0.02, nSteps = 300;

  function eulerSteps(x0, y0, forward) {
    const pts = [[x0, y0]];
    let x = x0, y = y0;
    const sign = forward ? 1 : -1;
    for (let s = 0; s &lt; nSteps; s++) {
      const dx = a11 * x + a12 * y;
      const dy = a21 * x + a22 * y;
      x += sign * dt * dx;
      y += sign * dt * dy;
      if (Math.abs(x) &gt; 6 || Math.abs(y) &gt; 6) break;
      pts.push([x, y]);
    }
    return pts;
  }

  const lineGen = d3.line()
    .x(p =&gt; xSc(p[0]))
    .y(p =&gt; ySc(p[1]))
    .defined(p =&gt; Math.abs(p[0]) &lt;= 3.2 && Math.abs(p[1]) &lt;= 3.2);

  for (let k = 0; k &lt; nTraj; k++) {
    const angle = (2 * Math.PI * k) / nTraj;
    const x0 = r0 * Math.cos(angle);
    const y0 = r0 * Math.sin(angle);

    const fwd = eulerSteps(x0, y0, true);
    const bwd = eulerSteps(x0, y0, false).slice(1).reverse();
    const pts = [...bwd, ...fwd];

    // Colour saddle trajectories by quadrant (proxy)
    let color;
    if (stableColor === "saddle") {
      color = (k % 2 === 0) ? "#1e6fcc" : "#cc3333";
    } else {
      color = trajColor;
    }

    g.append("path")
      .datum(pts)
      .attr("d", lineGen)
      .attr("fill", "none")
      .attr("stroke", color)
      .attr("stroke-width", 1.4)
      .attr("opacity", 0.75);
  }

  // Equilibrium dot at origin
  g.append("circle")
    .attr("cx", xSc(0)).attr("cy", ySc(0))
    .attr("r", 5)
    .attr("fill", stableColor === "stable" ? "#1e6fcc" : stableColor === "unstable" ? "#cc3333" : "#888")
    .attr("stroke", "#333").attr("stroke-width", 1.5);

  // Classification label
  const labelColor = stableColor === "stable" ? "#1e6fcc" : stableColor === "unstable" ? "#cc3333" : "#555";
  g.append("text")
    .attr("x", iW / 2).attr("y", iH + 30)
    .attr("text-anchor", "middle")
    .attr("font-size", 13).attr("font-weight", "bold")
    .attr("fill", labelColor)
    .text(`${classification}  |  λ₁ = ${lamStr1},  λ₂ = ${lamStr2}`);

  return svg.node();
}

38.6 Lotka-Volterra predator-prey

38.6.1 The equations
The Lotka-Volterra model for a prey population \(x\) (rabbits) and predator population \(y\) (foxes) is:
\[\begin{aligned}
x' &= ax - bxy \\
y' &= -dy + cxy
\end{aligned}\]
All parameters \(a, b, c, d &gt; 0\).

\(ax\): prey grow exponentially in the absence of predators.
\(-bxy\): prey are removed at a rate proportional to encounters with predators.
\(-dy\): predators decline exponentially in the absence of prey.
\(cxy\): predators grow from encounters with prey.



38.6.2 Equilibria
Set \(x' = 0\) and \(y' = 0\):
\[x(a - by) = 0 \quad \text{and} \quad y(-d + cx) = 0\]
This gives two equilibria:

\((0, 0)\): both populations extinct.
\((d/c,\; a/b)\): coexistence equilibrium — both populations positive.



38.6.3 Classifying via the Jacobian
\[\mathbf{f}(x,y) = \begin{pmatrix} ax - bxy \\ -dy + cxy \end{pmatrix}, \qquad J = \begin{pmatrix} a - by & -bx \\ cy & -d + cx \end{pmatrix}\]
At \((0,0)\):
\[J(0,0) = \begin{pmatrix} a & 0 \\ 0 & -d \end{pmatrix}\]
Eigenvalues: \(\lambda_1 = a &gt; 0\), \(\lambda_2 = -d &lt; 0\). A saddle. The extinction equilibrium is unstable — any positive initial population will move away from it.
At \((d/c,\; a/b)\):
Substituting \(x^* = d/c\), \(y^* = a/b\):
\[J(x^*, y^*) = \begin{pmatrix} 0 & -bd/c \\ ca/b & 0 \end{pmatrix}\]
Characteristic polynomial: \(\lambda^2 + ad = 0\), giving \(\lambda = \pm i\sqrt{ad}\).
Purely imaginary eigenvalues. The linearisation gives a centre. (For the full Lotka-Volterra system it can be shown, using a conserved quantity, that the nonlinear equilibrium is also a true centre — the populations cycle indefinitely around the coexistence point.)


38.6.4 Physical interpretation
The coexistence equilibrium \((d/c, a/b)\) is a neutrally stable centre. The populations do not converge to these values; instead, they cycle around them. The amplitude of the cycle depends on the initial conditions. Start with many rabbits and few foxes: the fox population grows, rabbit numbers fall, fox numbers eventually fall too, then rabbits recover. The cycle is closed.
This explains the wildlife warden’s observation: the populations oscillate, neither dying out nor converging to a constant value, with the phase plane orbit a closed curve around the coexistence point.


