  const d3 = await require("d3@7");

  const a  = lvParams.lvA;
  const b  = lvParams.lvB;
  const c  = lvParams.lvC;
  const d  = lvParams.lvD;
  const x0 = lvParams.lvX0;
  const y0 = lvParams.lvY0;

  // RK4 integration of Lotka-Volterra
  const dt = 0.05, nSteps = 2000;
  const tMax = 100;
  const storeEvery = 1;  // store every step

  const xs = [x0], ys = [y0], ts = [0];
  let cx = x0, cy = y0, ct = 0;

  for (let i = 0; i &lt; nSteps; i++) {
    // RK4
    const k1x = a * cx       - b * cx * cy;
    const k1y = c * cx * cy  - d * cy;

    const mx2 = cx + 0.5 * dt * k1x;
    const my2 = cy + 0.5 * dt * k1y;
    const k2x = a * mx2      - b * mx2 * my2;
    const k2y = c * mx2*my2  - d * my2;

    const mx3 = cx + 0.5 * dt * k2x;
    const my3 = cy + 0.5 * dt * k2y;
    const k3x = a * mx3      - b * mx3 * my3;
    const k3y = c * mx3*my3  - d * my3;

    const mx4 = cx + dt * k3x;
    const my4 = cy + dt * k3y;
    const k4x = a * mx4      - b * mx4 * my4;
    const k4y = c * mx4*my4  - d * my4;

    cx = cx + (dt / 6) * (k1x + 2*k2x + 2*k3x + k4x);
    cy = cy + (dt / 6) * (k1y + 2*k2y + 2*k3y + k4y);
    ct += dt;

    // clamp to avoid blow-up
    if (cx &lt; 0) cx = 0;
    if (cy &lt; 0) cy = 0;

    xs.push(cx);
    ys.push(cy);
    ts.push(ct);

    if (ct &gt;= tMax) break;
  }

  // Equilibria
  const eqX = d / c;
  const eqY = a / b;

  // Layout: two panels side by side, total 560px wide
  const totalW = 560, panelW = 270, H = 300;
  const margin = { top: 24, right: 18, bottom: 40, left: 44 };
  const iW = panelW - margin.left - margin.right;
  const iH = H      - margin.top  - margin.bottom;

  const svg = d3.create("svg")
    .attr("width", totalW).attr("height", H)
    .style("font-family", "sans-serif");

  // ── Left panel: Phase portrait ──────────────────────────────────────────
  const gL = svg.append("g")
    .attr("transform", `translate(${margin.left}, ${margin.top})`);

  const xMax = Math.max(...xs) * 1.15 || 20;
  const yMax = Math.max(...ys) * 1.15 || 20;

  const xSc = d3.scaleLinear().domain([0, xMax]).range([0, iW]);
  const ySc = d3.scaleLinear().domain([0, yMax]).range([iH, 0]);

  // Background
  gL.append("rect").attr("width", iW).attr("height", iH)
    .attr("fill", "#fafafa").attr("stroke", "#ccc");

  // Trajectory
  const phaseLine = d3.line()
    .x((_, i) =&gt; xSc(xs[i]))
    .y((_, i) =&gt; ySc(ys[i]));

  gL.append("path")
    .datum(xs)
