  for (let i = 0; i &lt; N; i++) {
    const t = ts[i];
    const [k1y, k1v] = deriv(t,          y,                    v);
    const [k2y, k2v] = deriv(t + dt/2,   y + dt/2 * k1y,      v + dt/2 * k1v);
    const [k3y, k3v] = deriv(t + dt/2,   y + dt/2 * k2y,      v + dt/2 * k2v);
    const [k4y, k4v] = deriv(t + dt,     y + dt * k3y,         v + dt * k3v);
    y += (dt / 6) * (k1y + 2*k2y + 2*k3y + k4y);
    v += (dt / 6) * (k1v + 2*k2v + 2*k3v + k4v);
    ts[i+1] = t + dt;
    ys[i+1] = y;
  }

  // Layout
  const width = 560, height = 300;
  const margin = {top: 24, right: 24, bottom: 40, left: 50};
  const innerW = width  - margin.left - margin.right;
  const innerH = height - margin.top  - margin.bottom;

  const yAll = Array.from(ys);
  const yMax = Math.max(d3.max(yAll) * 1.15, 1.2);
  const yMin = Math.min(d3.min(yAll) * 1.1, -0.15);

  const xScale = d3.scaleLinear().domain([0, tEnd]).range([0, innerW]);
  const yScale = d3.scaleLinear().domain([yMin, yMax]).range([innerH, 0]);

  const svg = d3.create("svg")
    .attr("viewBox", `0 0 ${width} ${height}`)
    .attr("width", width)
    .attr("style", "font-family: sans-serif; font-size: 11px;");

  const g = svg.append("g")
    .attr("transform", `translate(${margin.left},${margin.top})`);

  // Steady-state dashed line
  g.append("line")
    .attr("x1", 0).attr("y1", yScale(1))
    .attr("x2", innerW).attr("y2", yScale(1))
    .attr("stroke", "#aaa")
    .attr("stroke-width", 1.5)
    .attr("stroke-dasharray", "6,4");

  g.append("text")
    .attr("x", innerW - 4).attr("y", yScale(1) - 5)
    .attr("text-anchor", "end")
    .attr("fill", "#888")
    .text("Steady state (y = 1)");

  // Switch time dashed line
  if (a &lt;= tEnd) {
    g.append("line")
      .attr("x1", xScale(a)).attr("y1", 0)
      .attr("x2", xScale(a)).attr("y2", innerH)
      .attr("stroke", "#bbb")
      .attr("stroke-width", 1.5)
      .attr("stroke-dasharray", "4,3");

    g.append("text")
      .attr("x", xScale(a) + 4).attr("y", 14)
      .attr("fill", "#999")
      .text(`Switch at t = ${a}`);
  }

  // Axes
  g.append("g").attr("transform", `translate(0,${yScale(0)})`).call(d3.axisBottom(xScale).ticks(10));
  g.append("g").call(d3.axisLeft(yScale).ticks(6));

  // Axis labels
  g.append("text").attr("x", innerW / 2).attr("y", innerH + 32)
    .attr("text-anchor", "middle").text("t (s)");
  g.append("text")
    .attr("transform", "rotate(-90)")
    .attr("x", -innerH / 2).attr("y", -38)
    .attr("text-anchor", "middle").text("y(t)");

  // Response curve
  const lineGen = d3.line()
    .x((_, i) =&gt; xScale(ts[i]))
    .y((v) =&gt; yScale(v));

  g.append("path")
    .datum(yAll)
    .attr("d", lineGen)
    .attr("fill", "none")
    .attr("stroke", "steelblue")
    .attr("stroke-width", 2.5);

  // Damping label
  const dampLabel = zeta &lt; 1 ? `Underdamped (ζ = ${zeta.toFixed(2)})` :
                    zeta === 1 ? "Critically damped" :
                    `Overdamped (ζ = ${zeta.toFixed(2)})`;
  g.append("text")
    .attr("x", 6).attr("y", 14)
    .attr("fill", "steelblue")
    .attr("font-size", "12px")
    .text(dampLabel);

  return svg.node();
}

