  const g = svg.append("g").attr("transform", `translate(${W/2},${H/2})`);

  const xScale = d3.scaleLinear([-6, 6], [-innerW/2, innerW/2]);
  const yScale = d3.scaleLinear([-6, 6], [innerH/2, -innerH/2]);

  g.append("line").attr("x1", xScale(-6)).attr("y1", yScale(0)).attr("x2", xScale(6)).attr("y2", yScale(0)).attr("stroke", "#cbd5e1");
  g.append("line").attr("x1", xScale(0)).attr("y1", yScale(-6)).attr("x2", xScale(0)).attr("y2", yScale(6)).attr("stroke", "#cbd5e1");

  const unitPts = d3.range(0, 2 * Math.PI + 0.1, 0.1).map(theta =&gt; [Math.cos(theta), Math.sin(theta)]);
  const lineGen = d3.line().x(d =&gt; xScale(d[0])).y(d =&gt; yScale(d[1]));

  g.append("path").datum(unitPts).attr("d", lineGen).attr("fill", "none").attr("stroke", "#9ca3af").attr("stroke-dasharray", "4,4").attr("stroke-width", 1.5);

  const transformedPath = g.append("path").attr("fill", "rgba(59, 130, 246, 0.1)").attr("stroke", "#3b82f6").attr("stroke-width", 2);

  const vecGroup = g.append("g");
  const e1Line = vecGroup.append("line").attr("stroke", "#f97316").attr("stroke-width", 2.5);
  const e1Head = vecGroup.append("polygon").attr("fill", "#f97316");
  const e1Label = vecGroup.append("text").attr("fill", "#c2410c").attr("font-size", "13px").attr("font-weight", "bold").style("text-shadow", "1px 1px 2px white");

  const e2Line = vecGroup.append("line").attr("stroke", "#10b981").attr("stroke-width", 2.5);
  const e2Head = vecGroup.append("polygon").attr("fill", "#10b981");
  const e2Label = vecGroup.append("text").attr("fill", "#047857").attr("font-size", "13px").attr("font-weight", "bold").style("text-shadow", "1px 1px 2px white");

  const statusText = container.append("div").style("text-align", "center").style("font-size", "0.95rem").style("font-weight", "bold").style("margin-top", "10px");

  function update() {
    const a = +sliderA.inp.property("value");
    const b = +sliderB.inp.property("value");
    const c = +sliderC.inp.property("value");
    const d = +sliderD.inp.property("value");

    sliderA.val.text(a.toFixed(1));
    sliderB.val.text(b.toFixed(1));
    sliderC.val.text(c.toFixed(1));
    sliderD.val.text(d.toFixed(1));

    const transPts = unitPts.map(pt =&gt; [a*pt[0] + b*pt[1], c*pt[0] + d*pt[1]]);
    transformedPath.datum(transPts).attr("d", lineGen);

    const tr = a + d;
    const det = a*d - b*c;
    const disc = tr*tr - 4*det;

    if (disc &gt;= 0) {
      const lam1 = (tr + Math.sqrt(disc)) / 2;
      const lam2 = (tr - Math.sqrt(disc)) / 2;

      statusText.text(`Real Eigenvalues: \u03BB\u2081 = ${lam1.toFixed(2)}, \u03BB\u2082 = ${lam2.toFixed(2)}`).style("color", "#1e293b");

      function getEigVec(lam) {
        if (Math.abs(b) &gt; 1e-6) return [b, lam - a];
        if (Math.abs(c) &gt; 1e-6) return [lam - d, c];
        return lam === a ? [1, 0] : [0, 1];
      }

      function drawVec(v, lam, line, head, labelTxt, labelStr) {
        const mag = Math.sqrt(v[0]*v[0] + v[1]*v[1]) || 1;
        const norm = [v[0]/mag, v[1]/mag];
        const endx = norm[0] * lam;
        const endy = norm[1] * lam;

        const sx = xScale(endx);
        const sy = yScale(endy);
        const ox = xScale(0);
        const oy = yScale(0);

        line.attr("x1", ox).attr("y1", oy).attr("x2", sx).attr("y2", sy).attr("visibility", "visible");

        if (Math.abs(lam) &gt; 0.1) {
          const angle = Math.atan2(sy - oy, sx - ox);
          const r = 8;
          head.attr("points", `${sx},${sy} ${sx - r*Math.cos(angle - 0.5)},${sy - r*Math.sin(angle - 0.5)} ${sx - r*Math.cos(angle + 0.5)},${sy - r*Math.sin(angle + 0.5)}`).attr("visibility", "visible");
        } else {
          head.attr("visibility", "hidden");
        }

        labelTxt.attr("x", sx + 12*Math.sign(sx-ox)).attr("y", sy + 12*Math.sign(sy-oy)-5).text(labelStr).attr("visibility", "visible");
      }

      drawVec(getEigVec(lam1), lam1, e1Line, e1Head, e1Label, `\u03BB\u2081=${lam1.toFixed(2)}`);
      drawVec(getEigVec(lam2), lam2, e2Line, e2Head, e2Label, `\u03BB\u2082=${lam2.toFixed(2)}`);

    } else {
      statusText.text("Complex Eigenvalues (pure rotation/scaling without invariant axes)").style("color", "#dc2626");
      e1Line.attr("visibility", "hidden"); e1Head.attr("visibility", "hidden"); e1Label.attr("visibility", "hidden");
      e2Line.attr("visibility", "hidden"); e2Head.attr("visibility", "hidden"); e2Label.attr("visibility", "hidden");
    }
  }

  update();
  sliderA.inp.on("input", update);
  sliderB.inp.on("input", update);
  sliderC.inp.on("input", update);
  sliderD.inp.on("input", update);

  return container.node();
}

41.7 Applications

41.7.1 Vibrational modes of a two-mass spring system
Two masses connected by three springs form the simplest mechanical model of a multi-storey building or a coupled oscillator. With masses \(m_1 = 1\), \(m_2 = 2\) and spring constants \(k_1 = k_2 = k_3 = 1\):
The equations of motion are:
\[m_1 \ddot{u}_1 = -k_1 u_1 + k_2(u_2 - u_1) = -(k_1+k_2)u_1 + k_2 u_2\] \[m_2 \ddot{u}_2 = -k_2(u_2 - u_1) - k_3 u_2 = k_2 u_1 - (k_2+k_3)u_2\]
In matrix form \(M\ddot{\mathbf{u}} + K\mathbf{u} = \mathbf{0}\) with \(M = \text{diag}(1, 2)\):
\[K = \begin{pmatrix} 2 & -1 \\ -1 & 2 \end{pmatrix}\]
For harmonic motion \(\mathbf{u} = \mathbf{x} e^{i\omega t}\), this becomes the generalised eigenvalue problem:
\[K\mathbf{x} = \omega^2 M\mathbf{x}\]
Pre-multiply by \(M^{-1} = \text{diag}(1, \tfrac{1}{2})\):
\[M^{-1}K\mathbf{x} = \omega^2\mathbf{x}, \qquad M^{-1}K = \begin{pmatrix} 2 & -1 \\ -\tfrac{1}{2} & 1 \end{pmatrix}\]
Characteristic equation: \(\det(M^{-1}K - \omega^2 I) = 0\):
\[(2 - \omega^2)(1 - \omega^2) - \tfrac{1}{2} = 0\]
\[\omega^4 - 3\omega^2 + \tfrac{3}{2} = 0\]
Using the quadratic formula with \(\mu = \omega^2\):
\[\mu = \frac{3 \pm \sqrt{9 - 6}}{2} = \frac{3 \pm \sqrt{3}}{2}\]
\[\omega_1^2 = \frac{3 - \sqrt{3}}{2} \approx 0.634, \quad \omega_1 \approx 0.796 \text{ rad/s}\] \[\omega_2^2 = \frac{3 + \sqrt{3}}{2} \approx 2.366, \quad \omega_2 \approx 1.538 \text{ rad/s}\]
These are the two natural frequencies. At \(\omega_1\), both masses oscillate in phase (the first mode shape). At \(\omega_2\), they oscillate out of phase (the second mode shape). If you drive this system at either of these frequencies, resonance occurs — amplitudes grow without bound (in the undamped model).


41.7.2 Power iteration and PageRank
Google’s PageRank assigns importance scores to web pages based on the link structure of the web. Define the transition matrix \(G\) (the “Google matrix”) where \(G_{ij}\) is proportional to the probability of following a link from page \(j\) to page \(i\).
PageRank scores are the entries of the dominant eigenvector of \(G\) — the eigenvector corresponding to the largest eigenvalue (which is always 1 for a properly normalised transition matrix).
Finding the exact dominant eigenvector of a billion-by-billion matrix is impossible by direct methods. Instead, Google uses power iteration:

Start with any vector \(\mathbf{v}^{(0)}\) (e.g., uniform: all pages equally likely).
Multiply: \(\mathbf{v}^{(k+1)} = G\mathbf{v}^{(k)}\).
Normalise: divide by \(\|\mathbf{v}^{(k+1)}\|\).
Repeat until convergence.

Under mild conditions, this converges to the dominant eigenvector. The convergence rate depends on the ratio \(|\lambda_2/\lambda_1|\) — how much smaller the second eigenvalue is than the first.


