  function partialSum(x, N, waveType) {
    let s = 0;
    for (let n = 1; n &lt;= N; n++) s += bCoeff(n, waveType) * Math.sin(n * x);
    return s;
  }

  // Gibbs overshoot x-position (first peak of partial sum near x=0)
