    while (dang &gt; Math.PI) dang -= 2*Math.PI;
    while (dang &lt; -Math.PI) dang += 2*Math.PI;
    const laf = Math.abs(dang) &gt; Math.PI ? 1 : 0;
    const swf = dang &gt; 0 ? 1 : 0;
    arcPath.setAttribute("d", `M ${ax0} ${ay0} A ${arcR} ${arcR} 0 ${laf} ${swf} ${ax1e} ${ay1e}`);
    arcPath.setAttribute("fill","none"); arcPath.setAttribute("stroke","#8b5cf6");
    arcPath.setAttribute("stroke-width","1.5");
    svg.appendChild(arcPath);

    // Scale indicator: show |zw| / |z| = r label
    const zmag = Math.sqrt(zx*zx + zy*zy);
    const zwmag = Math.sqrt(zwx*zwx + zwy*zwy);

    // Points
    function makeCircle(px, py, radius, fill, stroke) {
      const c = document.createElementNS(svgNS, "circle");
      c.setAttribute("cx", px); c.setAttribute("cy", py); c.setAttribute("r", radius);
      c.setAttribute("fill", fill); c.setAttribute("stroke", stroke); c.setAttribute("stroke-width","1.5");
      return c;
    }
    svg.appendChild(makeCircle(zsx, zsy, 7, "#f97316", "#fff"));
    svg.appendChild(makeCircle(zwsx, zwsy, 7, "#3b82f6", "#fff"));
    svg.appendChild(makeCircle(ox, oy, 4, "#6b7280", "#fff"));

    // Labels
    function makeText(x, y, txt, color, size) {
      const t = document.createElementNS(svgNS, "text");
      t.setAttribute("x", x); t.setAttribute("y", y);
      t.setAttribute("fill", color); t.setAttribute("font-size", size || "12");
      t.setAttribute("font-family", "sans-serif");
      t.textContent = txt;
      return t;
    }
    svg.appendChild(makeText(zsx+8, zsy-6, "z", "#f97316", "13"));
    svg.appendChild(makeText(zwsx+8, zwsy-6, "zw", "#3b82f6", "13"));
    svg.appendChild(makeText(ox+4, oy-5, "O", "#6b7280", "11"));

    // Annotation
    const midArcX = CX + arcR * Math.cos((zAngle+zwAngle)/2);
    const midArcY = CY + arcR * Math.sin((zAngle+zwAngle)/2);
    svg.appendChild(makeText(midArcX - 5, midArcY - 8, "\u03b8", "#8b5cf6", "12"));

    // Info panel
    const info = document.createElement("div");
    info.style.cssText = "margin-top:0.5rem; font-size:0.85em; color:#374151; font-family:sans-serif; display:flex; gap:1.5rem; flex-wrap:wrap;";
    const thetaDeg = (theta * 180 / Math.PI).toFixed(0);
    info.innerHTML = `
      &lt;span style="color:#f97316"&gt;|z| = ${zmag.toFixed(2)}&lt;/span&gt;
      &lt;span style="color:#3b82f6"&gt;|zw| = ${zwmag.toFixed(2)}&lt;/span&gt;
      &lt;span style="color:#8b5cf6"&gt;arg(w) = ${thetaDeg}°&lt;/span&gt;
      &lt;span style="color:#6b7280"&gt;|zw|/|z| = ${r.toFixed(2)} = r&lt;/span&gt;
    `;

    const note = document.createElement("div");
    note.style.cssText = "margin-top:0.4rem; font-size:0.82em; color:#6b7280; font-style:italic;";
    note.textContent = `Multiplying by w = r·e^{iθ} rotates z by θ = ${thetaDeg}° and scales by r = ${r.toFixed(2)}. Orange point z, blue point zw. Set r = 1 for pure rotation; θ = 0 for pure scaling.`;

    const wrap = document.createElement("div");
    wrap.style.cssText = "margin:1rem 0;";
    wrap.appendChild(svg);
    wrap.appendChild(info);
    wrap.appendChild(note);
    return wrap;
  }

  const container = document.createElement("div");
  container.style.cssText = "border:1px solid #e5e7eb; border-radius:8px; padding:1rem; margin:1rem 0;";

  const title = document.createElement("div");
  title.style.cssText = "font-weight:600; margin-bottom:0.5rem; font-family:sans-serif;";
  title.textContent = "Complex multiplication as rotation and scaling";
  container.appendChild(title);

  container.appendChild(rSlider);
  container.appendChild(thetaSlider);

  const vizContainer = document.createElement("div");
  container.appendChild(vizContainer);

  function update() {
    const r = rSlider.value;
    const theta = thetaSlider.value;
    vizContainer.innerHTML = "";
    vizContainer.appendChild(makeViz(r, theta));
  }

  rSlider.addEventListener("input", update);
  thetaSlider.addEventListener("input", update);
  update();

  return container;
}

47.3 Complex differentiability
The derivative of \(f\) at \(z_0\) is:
\[f'(z_0) = \lim_{z \to z_0} \frac{f(z) - f(z_0)}{z - z_0}\]
The limit must exist and agree no matter how \(z\) approaches \(z_0\) — a far stronger requirement than real differentiability.

47.3.1 Deriving the Cauchy-Riemann equations
The key idea is that the limit \([f(z)-f(z_0)]/(z-z_0)\) must give the same answer regardless of the direction of approach. The two simplest directions — horizontal and vertical — already force a constraint on \(u\) and \(v\).


