          d[idx]   = Math.round(180 + err*75);
          d[idx+1] = Math.round(180 - err*150);
          d[idx+2] = Math.round(180 - err*150);
          d[idx+3] = 255;
        } else {
          const fv = component === "u" ? getU(name,re,im) : getV(name,re,im);
          if (!isFinite(fv)) { d[idx]=255; d[idx+1]=255; d[idx+2]=255; d[idx+3]=255; continue; }
          const t = Math.max(0, Math.min(1, (fv-fmin)/frange));
