    // Iso-contours via marching squares (simplified: draw line segments)
    function isoContour(field, level, color, alpha) {
      ctx.beginPath(); ctx.strokeStyle = color; ctx.lineWidth = 0.9;
      ctx.globalAlpha = alpha;
      const step = 3;
      for (let px=0; px&lt;W-step; px+=step) {
        for (let py=0; py&lt;H-step; py+=step) {
          const re=(px-CX)/SCALE, im=-(py-CY)/SCALE;
          const v00=field(name,re,im),   v10=field(name,re+step/SCALE,im);
          const v01=field(name,re,im-step/SCALE), v11=field(name,re+step/SCALE,im-step/SCALE);
          const c0=(v00&gt;level), c1=(v10&gt;level), c2=(v11&gt;level), c3=(v01&gt;level);
          if (c0===c1 && c1===c2 && c2===c3) continue;
          function interp(v0,v1,x0,y0,x1,y1) {
            if (Math.abs(v1-v0)&lt;1e-9) return [(x0+x1)/2,(y0+y1)/2];
            const t=(level-v0)/(v1-v0);
            return [x0+(x1-x0)*t, y0+(y1-y0)*t];
          }
          const pts=[];
          if (c0!==c1) pts.push(interp(v00,v10, px,py, px+step,py));
          if (c1!==c2) pts.push(interp(v10,v11, px+step,py, px+step,py+step));
          if (c3!==c2) pts.push(interp(v01,v11, px,py+step, px+step,py+step));
          if (c0!==c3) pts.push(interp(v00,v01, px,py, px,py+step));
          if (pts.length&gt;=2) {
            ctx.moveTo(pts[0][0],pts[0][1]); ctx.lineTo(pts[1][0],pts[1][1]);
          }
        }
      }
      ctx.stroke(); ctx.globalAlpha=1;
    }

