  }

  function renderProbeOverlay(canvas, name, ptx, pty, component) {
    const ctx = canvas.getContext("2d");
    const [psx, psy] = [CX + ptx*SCALE, CY - pty*SCALE];
    ctx.fillStyle = "#f97316"; ctx.strokeStyle="#fff"; ctx.lineWidth=1.5;
    ctx.beginPath(); ctx.arc(psx,psy,5,0,2*Math.PI); ctx.fill(); ctx.stroke();
    // Gradient arrow
    const eps = 0.06;
    const gx = component==="u" ? (getU(name,ptx+eps,pty)-getU(name,ptx-eps,pty))/(2*eps)
                                : (getV(name,ptx+eps,pty)-getV(name,ptx-eps,pty))/(2*eps);
    const gy = component==="u" ? (getU(name,ptx,pty+eps)-getU(name,ptx,pty-eps))/(2*eps)
                                : (getV(name,ptx,pty+eps)-getV(name,ptx,pty-eps))/(2*eps);
    const gLen = Math.sqrt(gx*gx+gy*gy)||1;
    const scale = 18;
    const ex = psx + (gx/gLen)*scale, ey = psy - (gy/gLen)*scale;
    ctx.strokeStyle="#f97316"; ctx.lineWidth=2;
    ctx.beginPath(); ctx.moveTo(psx,psy); ctx.lineTo(ex,ey); ctx.stroke();
  }

