    c.setAttribute("fill",fill);c.setAttribute("stroke",stroke||"#fff");c.setAttribute("stroke-width","1.5");
    svg.appendChild(c);
  }
  function addText(svg,x,y,txt,color,size){
    const t=document.createElementNS(svgNS,"text");
    t.setAttribute("x",x);t.setAttribute("y",y);t.setAttribute("fill",color);
    t.setAttribute("font-size",size||"11");t.setAttribute("font-family","sans-serif");
    t.textContent=txt; svg.appendChild(t);
  }
  function makeSVG(label){
    const svg=document.createElementNS(svgNS,"svg");
    svg.setAttribute("width",W); svg.setAttribute("height",H);
    svg.style.cssText="background:#fafafa; border:1px solid #e5e7eb; border-radius:6px; display:block;";
    // Grid
    for(let i=-3;i&lt;=3;i++){
      const xl=document.createElementNS(svgNS,"line");
      const [lx]=toScreen(i,0,CX,CY,SCALE); xl.setAttribute("x1",lx);xl.setAttribute("y1","0");xl.setAttribute("x2",lx);xl.setAttribute("y2",H);
      xl.setAttribute("stroke","#e5e7eb");xl.setAttribute("stroke-width","0.5");svg.appendChild(xl);
      const yl=document.createElementNS(svgNS,"line");
      const [,ly]=toScreen(0,i,CX,CY,SCALE); yl.setAttribute("x1","0");yl.setAttribute("y1",ly);yl.setAttribute("x2",W);yl.setAttribute("y2",ly);
      yl.setAttribute("stroke","#e5e7eb");yl.setAttribute("stroke-width","0.5");svg.appendChild(yl);
    }
    addLine(svg,0,CY,W,CY,"#9ca3af","1");
    addLine(svg,CX,0,CX,H,"#9ca3af","1");
    addText(svg,6,14,label,"#1f2937","11");
    return svg;
  }

  function buildViz(fn, z0x, z0y, a1, a2) {
    const svgL = makeSVG("z-plane");
    const svgR = makeSVG("w-plane");

    const ARM_LEN = 0.9; // in complex units

    // Arm end-points in z-plane
    const z1r = z0x + ARM_LEN*Math.cos(a1), z1i = z0y + ARM_LEN*Math.sin(a1);
    const z2r = z0x + ARM_LEN*Math.cos(a2), z2i = z0y + ARM_LEN*Math.sin(a2);

    // Draw z-plane arms
    const [z0sx,z0sy] = toScreen(z0x,z0y,CX,CY,SCALE);
    const [z1sx,z1sy] = toScreen(z1r,z1i,CX,CY,SCALE);
    const [z2sx,z2sy] = toScreen(z2r,z2i,CX,CY,SCALE);
    addLine(svgL,z0sx,z0sy,z1sx,z1sy,"#f97316","2.5");
    addLine(svgL,z0sx,z0sy,z2sx,z2sy,"#8b5cf6","2.5");
    addCircle(svgL,z0sx,z0sy,6,"#f97316");
    addText(svgL,z0sx+8,z0sy-6,"z₀","#f97316","12");

    // Input angle between arms
    const inputAngle = a2 - a1;

    // Map z₀ and arm endpoints
    const [w0r,w0i] = evalF(fn,z0x,z0y);
    const [w1r,w1i] = evalF(fn,z1r,z1i);
    const [w2r,w2i] = evalF(fn,z2r,z2i);

    // Auto-scale w-plane around w₀
    const d1 = Math.sqrt((w1r-w0r)**2+(w1i-w0i)**2);
    const d2 = Math.sqrt((w2r-w0r)**2+(w2i-w0i)**2);
    const maxD = Math.max(d1,d2,0.1);
    const wSCALE = Math.min(SCALE, 80/(maxD));
    const wCX = W/2 - w0r*wSCALE, wCY = H/2 + w0i*wSCALE;

    function toWS(re,im){ return [wCX+re*wSCALE, wCY-im*wSCALE]; }

    if (isFinite(w0r) && isFinite(w0i)) {
      const [w0sx,w0sy]=toWS(w0r,w0i);
      const [w1sx,w1sy]=toWS(w1r,w1i);
      const [w2sx,w2sy]=toWS(w2r,w2i);
      addLine(svgR,w0sx,w0sy,w1sx,w1sy,"#f97316","2.5");
      addLine(svgR,w0sx,w0sy,w2sx,w2sy,"#8b5cf6","2.5");
      addCircle(svgR,w0sx,w0sy,6,"#f97316");
      addText(svgR,w0sx+8,w0sy-6,"f(z₀)","#3b82f6","11");

      // Output angle between arm images
      const out1 = Math.atan2(w1i-w0i, w1r-w0r);
      const out2 = Math.atan2(w2i-w0i, w2r-w0r);
      let outputAngle = out2 - out1;
      while (outputAngle &gt;  Math.PI) outputAngle -= 2*Math.PI;
      while (outputAngle &lt; -Math.PI) outputAngle += 2*Math.PI;
      let inputAngleN = inputAngle;
      while (inputAngleN &gt;  Math.PI) inputAngleN -= 2*Math.PI;
      while (inputAngleN &lt; -Math.PI) inputAngleN += 2*Math.PI;

      // Derivative magnitude for critical-point test
      const [fpRe,fpIm] = evalFPrime(fn,z0x,z0y);
      const fpMag = Math.sqrt(fpRe*fpRe+fpIm*fpIm);
      const isCritical = fpMag &lt; 0.05;
      const isConj = fn === "f(z) = z̄";
      const angleDiff = Math.abs(Math.abs(outputAngle)-Math.abs(inputAngleN));
      const isConformal = !isCritical && !isConj && angleDiff &lt; 0.15;

      // Status badge
      let statusColor, statusMsg;
      if (isCritical) { statusColor="#dc2626"; statusMsg="Critical point: f'(z₀)≈0 — conformality fails"; }
      else if (isConj) { statusColor="#dc2626"; statusMsg="f=z̄: reflection — angles reversed (not conformal)"; }
      else if (isConformal) { statusColor="#059669"; statusMsg="Conformal: angles preserved"; }
      else { statusColor="#dc2626"; statusMsg="Angle mismatch — check critical point or branch"; }

      const badge=document.createElementNS(svgNS,"rect");
      badge.setAttribute("x","4"); badge.setAttribute("y",H-26);
      badge.setAttribute("width",W-8); badge.setAttribute("height","22");
      badge.setAttribute("fill",statusColor); badge.setAttribute("rx","4"); badge.setAttribute("opacity","0.15");
      svgR.appendChild(badge);
      const badgeTxt=document.createElementNS(svgNS,"text");
      badgeTxt.setAttribute("x","8"); badgeTxt.setAttribute("y",H-11);
      badgeTxt.setAttribute("fill",statusColor); badgeTxt.setAttribute("font-size","9.5");
      badgeTxt.setAttribute("font-family","sans-serif"); badgeTxt.textContent=statusMsg;
      svgR.appendChild(badgeTxt);

      // Angle readout in w-plane
      addText(svgR,6,H-32,`input angle: ${(inputAngleN*180/Math.PI).toFixed(1)}°  →  output: ${(outputAngle*180/Math.PI).toFixed(1)}°`,"#374151","9.5");
    } else {
      addText(svgR,W/2-40,H/2,"(pole — undefined)","#dc2626","11");
    }

    const wrap=document.createElement("div");
    wrap.style.cssText="display:flex; gap:0.75rem; flex-wrap:wrap; margin:0.5rem 0;";
    wrap.appendChild(svgL); wrap.appendChild(svgR);
    return wrap;
  }

  const container=document.createElement("div");
  container.style.cssText="border:1px solid #e5e7eb; border-radius:8px; padding:1rem; margin:1rem 0;";

  const titleEl=document.createElement("div");
  titleEl.style.cssText="font-weight:600; margin-bottom:0.5rem; font-family:sans-serif;";
  titleEl.textContent="Conformal mapping: angle-preservation test";
  container.appendChild(titleEl);
  container.appendChild(funcSel);
  container.appendChild(z0xSl);
  container.appendChild(z0ySl);
  container.appendChild(arm1Sl);
  container.appendChild(arm2Sl);

  const vizDiv=document.createElement("div"); container.appendChild(vizDiv);

  const noteEl=document.createElement("div");
  noteEl.style.cssText="margin-top:0.4rem; font-size:0.82em; color:#6b7280; font-style:italic;";
  noteEl.textContent="Orange and purple arms cross at z₀ in the left panel. Their images cross at f(z₀) in the right panel. The angle between the images (bottom of right panel) equals the input angle when f is conformal. Move z₀ onto a critical point (f′(z₀) = 0, e.g. z₀ = 0 for f = z²) to see conformality fail. Select f = z̄ to see that a reflection reverses angles instead of preserving them.";
  container.appendChild(noteEl);

  function update() {
    vizDiv.innerHTML="";
    vizDiv.appendChild(buildViz(funcSel.value, z0xSl.value, z0ySl.value, arm1Sl.value, arm2Sl.value));
  }
  funcSel.addEventListener("input",update);
  z0xSl.addEventListener("input",update);
  z0ySl.addEventListener("input",update);
  arm1Sl.addEventListener("input",update);
  arm2Sl.addEventListener("input",update);
  update();

  return container;
}

