  const STEPS = 400;

  const intSelector = Inputs.select(
    ["f(z) = z  (analytic)", "f(z) = z\u0305  (not analytic)", "f(z) = |z|\u00b2  (not analytic)"],
    { value: "f(z) = z  (analytic)", label: "Integrand" }
  );
