48.1.1 The ML inequality
When you need a bound on a contour integral rather than its exact value, the ML inequality is the standard tool:
\[\left|\int_C f(z)\,dz\right| \leq M \cdot L\]
where \(M = \max_{z \in C}|f(z)|\) and \(L\) is the arc length of \(C\). This mirrors the real estimate \(|\int_a^b f\,dx| \leq \max|f| \cdot (b-a)\). The application section below shows how to read off \(M\) and \(L\) in practice.


Code
// VIZ 6: ML inequality geometry
// Contour in z-plane with perpendicular spike magnitudes; M and L labels;
// bounding rectangle vs actual integral bar in right panel.
{
  const W = 340, H = 260, SCALE = 70, OX = 100, OY = 160;
  const svgNS = "http://www.w3.org/2000/svg";
  const STEPS = 120;

  const radiusML = Inputs.range([0.4, 2.2], { value: 1.2, step: 0.05, label: "Contour radius R" });
  const funcML = Inputs.select(
    ["f(z) = 1/z\u00b2", "f(z) = e^z", "f(z) = 1/(z+2)"],
    { value: "f(z) = 1/z\u00b2", label: "f(z)" }
  );

  function toSx(re) { return OX + re * SCALE; }
  function toSy(im) { return OY - im * SCALE; }

  function fMagnitude(fname, re, im) {
    if (fname === "f(z) = 1/z\u00b2") {
      const d2 = re*re + im*im;
      return d2 &lt; 1e-8 ? 99 : 1 / d2;
    }
    if (fname === "f(z) = e^z") return Math.exp(re);
    const dr = re + 2, d = dr*dr + im*im;
    return d &lt; 1e-10 ? 99 : 1 / Math.sqrt(d);
  }

  function build(R, fname) {
    const svg = document.createElementNS(svgNS, "svg");
    svg.setAttribute("width", W); svg.setAttribute("height", H);
    svg.style.cssText = "background:#fafafa; border:1px solid #e5e7eb; border-radius:6px; display:block;";

    // Axes
    for (const [x1,y1,x2,y2] of [
      [toSx(-0.2), toSy(0), toSx(2.4), toSy(0)],
      [toSx(0), toSy(-1.8), toSx(0), toSy(2.0)]
    ]) {
      const ax = document.createElementNS(svgNS, "line");
      ax.setAttribute("x1",x1); ax.setAttribute("y1",y1);
      ax.setAttribute("x2",x2); ax.setAttribute("y2",y2);
      ax.setAttribute("stroke","#d1d5db"); ax.setAttribute("stroke-width","1");
      svg.appendChild(ax);
    }

    // Contour circle and spike magnitudes
    const mags = [];
    let dPath = "";
    for (let k = 0; k &lt;= STEPS; k++) {
      const theta = (2 * Math.PI * k) / STEPS;
      const re = R * Math.cos(theta), im = R * Math.sin(theta);
      const m = fMagnitude(fname, re, im);
      mags.push(Math.min(m, 4)); // cap display
      dPath += (k === 0 ? "M" : "L") + ` ${toSx(re)} ${toSy(im)}`;
    }
    const contour = document.createElementNS(svgNS, "path");
    contour.setAttribute("d", dPath); contour.setAttribute("fill", "none");
    contour.setAttribute("stroke", "#3b82f6"); contour.setAttribute("stroke-width", "2");
    svg.appendChild(contour);

    // Spikes
    const SPIKE_SCALE = 20;
    for (let k = 0; k &lt; STEPS; k += 6) {
      const theta = (2 * Math.PI * k) / STEPS;
      const re = R * Math.cos(theta), im = R * Math.sin(theta);
      const sx = toSx(re), sy = toSy(im);
      // Outward normal direction
      const nx = Math.cos(theta), ny = -Math.sin(theta); // screen normal (y flipped)
      const h = Math.min(mags[k], 3.5) * SPIKE_SCALE;
      const ex = sx + nx * h, ey = sy + ny * h;
      const spike = document.createElementNS(svgNS, "line");
      spike.setAttribute("x1", sx); spike.setAttribute("y1", sy);
      spike.setAttribute("x2", ex); spike.setAttribute("y2", ey);
      spike.setAttribute("stroke", "#f97316"); spike.setAttribute("stroke-width", "1.5");
      spike.setAttribute("opacity", "0.7");
      svg.appendChild(spike);
    }

    // M = max on contour, L = arc length = 2πR
    const Mval = Math.max(...mags);
    const Lval = 2 * Math.PI * R;
    const ML = Mval * Lval;

    // M level ring
    const mlCircle = document.createElementNS(svgNS, "circle");
    mlCircle.setAttribute("cx", toSx(0)); mlCircle.setAttribute("cy", toSy(0));
    mlCircle.setAttribute("r", (R + Math.min(Mval, 3.5) * (SPIKE_SCALE / SCALE)));
    mlCircle.setAttribute("fill", "none"); mlCircle.setAttribute("stroke", "#dc2626");
    mlCircle.setAttribute("stroke-width", "1"); mlCircle.setAttribute("stroke-dasharray", "3,3");
    svg.appendChild(mlCircle);

    // Labels
    const mlbl = document.createElementNS(svgNS, "text");
    mlbl.setAttribute("x", toSx(R) + 4); mlbl.setAttribute("y", toSy(0) - 4);
    mlbl.setAttribute("font-size", "10"); mlbl.setAttribute("fill", "#f97316");
    mlbl.setAttribute("font-family", "sans-serif"); mlbl.textContent = "M = " + Mval.toFixed(2);
    svg.appendChild(mlbl);
    const llbl = document.createElementNS(svgNS, "text");
    llbl.setAttribute("x", toSx(0) + 4); llbl.setAttribute("y", toSy(-R) + 14);
    llbl.setAttribute("font-size", "10"); llbl.setAttribute("fill", "#3b82f6");
    llbl.setAttribute("font-family", "sans-serif"); llbl.textContent = "L = 2\u03c0R = " + Lval.toFixed(2);
    svg.appendChild(llbl);

    // Contour label
    const clbl = document.createElementNS(svgNS, "text");
    clbl.setAttribute("x", 4); clbl.setAttribute("y", 14);
    clbl.setAttribute("font-size", "10"); clbl.setAttribute("fill", "#3b82f6");
    clbl.setAttribute("font-family", "sans-serif"); clbl.textContent = "C: |z| = " + R.toFixed(2);
    svg.appendChild(clbl);

    // Bar panel on right
    const BX = W - 100, BY = 20, BW = 80, BH = H - 50;
    const bg = document.createElementNS(svgNS, "rect");
    bg.setAttribute("x", BX); bg.setAttribute("y", BY);
    bg.setAttribute("width", BW); bg.setAttribute("height", BH);
    bg.setAttribute("fill", "#f9fafb"); bg.setAttribute("rx", "4");
    svg.appendChild(bg);

    // Actual |∮ f dz| — numerical estimate via trapezoidal sum
    let sumRe = 0, sumIm = 0;
    for (let k = 0; k &lt; STEPS; k++) {
      const t0 = (2*Math.PI*k)/STEPS, t1 = (2*Math.PI*(k+1))/STEPS;
      const r0 = R*Math.cos(t0), i0 = R*Math.sin(t0);
      const r1 = R*Math.cos(t1), i1 = R*Math.sin(t1);
      const mr = (r0+r1)/2, mi = (i0+i1)/2;
      const dr = r1-r0, di = i1-i0;
      // f(z) evaluation
      let fr, fi;
      if (fname === "f(z) = 1/z\u00b2") {
        const d2 = mr*mr+mi*mi; if (d2&lt;1e-8) continue;
        const re2 = (mr*mr-mi*mi)/(d2*d2), im2 = (-2*mr*mi)/(d2*d2);
        fr = re2; fi = im2;
      } else if (fname === "f(z) = e^z") {
        fr = Math.exp(mr)*Math.cos(mi); fi = Math.exp(mr)*Math.sin(mi);
      } else {
        const ddr = mr+2, d = ddr*ddr+mi*mi; if (d&lt;1e-10) continue;
        fr = ddr/d; fi = -mi/d;
      }
      sumRe += fr*dr - fi*di;
      sumIm += fi*dr + fr*di;
    }
    const actual = Math.sqrt(sumRe*sumRe + sumIm*sumIm);
    const maxBar = Math.max(ML, actual, 0.1);
    const mlH = (ML / maxBar) * (BH - 30);
    const actH = (actual / maxBar) * (BH - 30);

