// VIZ 2: Contour deformation and singularity switch
// Domain-coloured background; bulge slider morphs contour from excluding to including origin;
// integral readout jumps from 0 to 2πi; winding number counter; optional second singularity.
{
  const W = 360, H = 320, SCALE = 70, CX = W / 2, CY = H / 2;
  const svgNS = "http://www.w3.org/2000/svg";
  const STEPS = 360;

  const bulgeSlider = Inputs.range([-1.5, 1.5], { value: -0.8, step: 0.025, label: "Bulge (−: exclude origin, +: include)" });
  const secondSing = Inputs.toggle({ label: "Add second singularity at z = 1.5", value: false });

  function toSx(re) { return CX + re * SCALE; }
  function toSy(im) { return CY - im * SCALE; }

  // Deformable contour C2: base circle of radius 1.8, bulged toward/away from origin
  // bulge &gt; 0 means the contour bows inward toward origin, eventually enclosing it
  function contourC2(theta, bulge) {
    // Offset the radius at each angle: bulge shifts the leftmost point
    // r(theta) = 1.8 + bulge * cos(theta)  (max deformation along Re axis)
    const r = 1.8 + bulge * Math.cos(theta);
    return [r * Math.cos(theta), r * Math.sin(theta)];
  }

  function pointInContour(px, py, bulge) {
    // Ray-casting: count crossings from (px,py) in +x direction
    let crossings = 0;
    for (let k = 0; k &lt; STEPS; k++) {
      const t0 = (2 * Math.PI * k) / STEPS;
      const t1 = (2 * Math.PI * (k + 1)) / STEPS;
      const [x0, y0] = contourC2(t0, bulge);
      const [x1, y1] = contourC2(t1, bulge);
      if ((y0 &lt;= py && y1 &gt; py) || (y1 &lt;= py && y0 &gt; py)) {
        const xIntersect = x0 + ((py - y0) / (y1 - y0)) * (x1 - x0);
        if (px &lt; xIntersect) crossings++;
      }
    }
    return crossings % 2 === 1;
  }

  function computeC2Integral(bulge, singRe, singIm) {
    // ∮ 1/(z - sing) dz numerically
    let rSum = 0, iSum = 0;
    for (let k = 0; k &lt; STEPS; k++) {
      const t0 = (2 * Math.PI * k) / STEPS;
      const t1 = (2 * Math.PI * (k + 1)) / STEPS;
      const [r0, i0] = contourC2(t0, bulge);
      const [r1, i1] = contourC2(t1, bulge);
      const mr = (r0 + r1) / 2, mi = (i0 + i1) / 2;
      const dr = r1 - r0, di = i1 - i0;
      const denom = (mr - singRe) ** 2 + (mi - singIm) ** 2;
      if (denom &lt; 1e-8) continue;
      const fr = (mr - singRe) / denom, fi = -(mi - singIm) / denom;
      rSum += fr * dr - fi * di;
      iSum += fi * dr + fr * di;
    }
    return [rSum, iSum];
