  function hslToRgb(h, s, l) {
    h = ((h % 1) + 1) % 1;
    const c = (1 - Math.abs(2 * l - 1)) * s;
    const x = c * (1 - Math.abs(((h * 6) % 2) - 1));
    const m = l - c / 2;
    let r = 0, g = 0, b = 0;
    if (h &lt; 1/6) { r = c; g = x; }
    else if (h &lt; 2/6) { r = x; g = c; }
    else if (h &lt; 3/6) { g = c; b = x; }
    else if (h &lt; 4/6) { g = x; b = c; }
    else if (h &lt; 5/6) { r = x; b = c; }
    else { r = c; b = x; }
    return [Math.round((r+m)*255), Math.round((g+m)*255), Math.round((b+m)*255)];
  }

  function render(bulge, showSecond) {
    // Canvas for domain colouring
    const canvas = document.createElement("canvas");
    canvas.width = W; canvas.height = H;
    const ctx = canvas.getContext("2d");
    const img = ctx.createImageData(W, H);
    const data = img.data;

    for (let px = 0; px &lt; W; px++) {
      for (let py = 0; py &lt; H; py++) {
        const re = (px - CX) / SCALE;
        const im = -(py - CY) / SCALE;
        // Colour by 1/z (primary singularity at origin)
        const d2 = re * re + im * im;
        let hue, brightness;
        if (d2 &lt; 1e-6) {
          const idx = (py * W + px) * 4;
          data[idx] = 255; data[idx+1] = 255; data[idx+2] = 255; data[idx+3] = 255;
          continue;
        }
        const wr = re / d2, wi = -im / d2;
        const arg = Math.atan2(wi, wr);
        const mag = Math.sqrt(wr*wr + wi*wi);
        hue = (arg / (2 * Math.PI) + 1) % 1;
        brightness = 0.45 + 0.3 * Math.tanh(Math.log(mag + 0.001) / 2);
        const [r, g, b] = hslToRgb(hue, 0.72, brightness);
        const idx = (py * W + px) * 4;
        data[idx] = r; data[idx+1] = g; data[idx+2] = b; data[idx+3] = 255;
      }
    }
    ctx.putImageData(img, 0, 0);

    // Fixed outer circle C1 (orange)
    const [ox, oy] = [toSx(0), toSy(0)];
    ctx.strokeStyle = "#f97316"; ctx.lineWidth = 2.5;
    ctx.beginPath(); ctx.arc(ox, oy, 2.5 * SCALE, 0, 2 * Math.PI); ctx.stroke();
    ctx.fillStyle = "#f97316"; ctx.font = "11px sans-serif";
    ctx.fillText("C\u2081 (fixed)", toSx(2.5) + 4, toSy(0));

    // Deformable contour C2 (blue)
    ctx.strokeStyle = "#3b82f6"; ctx.lineWidth = 2.5;
    ctx.beginPath();
    for (let k = 0; k &lt;= STEPS; k++) {
      const theta = (2 * Math.PI * k) / STEPS;
      const [cr, ci] = contourC2(theta, bulge);
      const sx = toSx(cr), sy = toSy(ci);
      k === 0 ? ctx.moveTo(sx, sy) : ctx.lineTo(sx, sy);
    }
    ctx.closePath(); ctx.stroke();
    ctx.fillStyle = "#3b82f6"; ctx.font = "11px sans-serif";
    ctx.fillText("C\u2082 (deformable)", toSx(-2.4), toSy(1.2));

    // Origin singularity ×
    ctx.strokeStyle = "#fff"; ctx.lineWidth = 2.5;
    ctx.beginPath(); ctx.moveTo(ox-7, oy-7); ctx.lineTo(ox+7, oy+7); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(ox+7, oy-7); ctx.lineTo(ox-7, oy+7); ctx.stroke();
    ctx.fillStyle = "#fff"; ctx.font = "9px sans-serif"; ctx.fillText("1/z", ox+10, oy-5);

    // Second singularity at z=1.5
    if (showSecond) {
      const [sx2, sy2] = [toSx(1.5), toSy(0)];
      ctx.strokeStyle = "#dc2626"; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.moveTo(sx2-6, sy2-6); ctx.lineTo(sx2+6, sy2+6); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(sx2+6, sy2-6); ctx.lineTo(sx2-6, sy2+6); ctx.stroke();
      ctx.fillStyle = "#dc2626"; ctx.font = "9px sans-serif"; ctx.fillText("1/(z-1.5)", sx2+8, sy2-4);
    }

    // Winding number box for C2 around origin
    const originInC2 = pointInContour(0, 0, bulge);
    const winding2 = originInC2 ? 1 : 0;
    ctx.fillStyle = "#1e40af";
    ctx.beginPath();
    ctx.roundRect(W - 92, 5, 86, 44, 5);
    ctx.fill();
    ctx.fillStyle = "white"; ctx.textAlign = "center";
    ctx.font = "10px sans-serif";
    ctx.fillText("n(C\u2082, 0)", W - 49, 21);
    ctx.font = "bold 18px sans-serif";
    ctx.fillText(winding2.toString(), W - 49, 41);
    ctx.textAlign = "left";

    return { canvas, originInC2, winding2 };
  }

  const container = document.createElement("div");
  container.style.cssText = "border:1px solid #e5e7eb; border-radius:8px; padding:1rem; margin:1rem 0; font-family:sans-serif;";

  const title = document.createElement("div");
  title.style.cssText = "font-weight:600; margin-bottom:0.5rem;";
  title.textContent = "Contour deformation: deforming C\u2082 past the singularity";
