  container.appendChild(bulgeSlider);
  container.appendChild(secondSing);

  const canvasDiv = document.createElement("div");
  container.appendChild(canvasDiv);

  const readout = document.createElement("div");
  readout.style.cssText = "margin-top:0.5rem; font-size:0.88em; display:grid; grid-template-columns:1fr 1fr; gap:0.5rem;";
  container.appendChild(readout);

  const noteEl = document.createElement("div");
  noteEl.style.cssText = "margin-top:0.5rem; font-size:0.82em; color:#6b7280; font-style:italic;";
  noteEl.textContent = "Drag the bulge slider left to exclude the origin (integral = 0) and right to enclose it (integral = 2\u03c0i). The fixed outer circle C\u2081 always encloses the singularity; C\u2082 starts outside and crosses through. Toggle the second singularity at z = 1.5 to see its separate contribution.";
  container.appendChild(noteEl);

  function update() {
    const bulge = bulgeSlider.value;
    const showSecond = secondSing.value;
    const { canvas, originInC2 } = render(bulge, showSecond);
    canvasDiv.innerHTML = ""; canvasDiv.appendChild(canvas);

    // Compute integrals
    const [c2Re, c2Im] = computeC2Integral(bulge, 0, 0);
    const c1Im = 2 * Math.PI; // always encloses origin
    let html = `&lt;div style="background:#fff7ed; border:1px solid #fed7aa; border-radius:4px; padding:0.4rem 0.6rem;"&gt;
      &lt;span style="color:#f97316; font-weight:600;"&gt;C\u2081:&lt;/span&gt;
      \u222e 1/z dz = 0 + ${c1Im.toFixed(4)}i = 2\u03c0i&lt;/div&gt;`;
    const c2Status = originInC2
      ? `&lt;span style="color:#059669; font-weight:600;"&gt;C\u2082 encloses origin \u2192 2\u03c0i&lt;/span&gt;`
      : `&lt;span style="color:#6b7280; font-weight:600;"&gt;C\u2082 excludes origin \u2192 0&lt;/span&gt;`;
    html += `&lt;div style="background:#eff6ff; border:1px solid #bfdbfe; border-radius:4px; padding:0.4rem 0.6rem;"&gt;
      &lt;span style="color:#3b82f6; font-weight:600;"&gt;C\u2082:&lt;/span&gt;
      \u222e 1/z dz \u2248 ${c2Re.toFixed(3)} + ${c2Im.toFixed(3)}i &nbsp; ${c2Status}&lt;/div&gt;`;

    if (showSecond) {
      const [s2Re, s2Im] = computeC2Integral(bulge, 1.5, 0);
      html += `&lt;div style="background:#fef2f2; border:1px solid #fecaca; border-radius:4px; padding:0.4rem 0.6rem; grid-column:1/-1;"&gt;
        &lt;span style="color:#dc2626; font-weight:600;"&gt;C\u2082 around 1/(z-1.5):&lt;/span&gt;
