48.4.2 Fundamental theorem of algebra
Every non-constant polynomial \(p(z)\) of degree \(n \geq 1\) has exactly \(n\) complex roots (counting multiplicity).
Proof sketch. If \(p\) had no roots, \(1/p(z)\) would be entire (no zeros means no poles) and bounded (since \(|p(z)| \to \infty\) as \(|z| \to \infty\), so \(|1/p(z)| \to 0\)), contradicting Liouville’s theorem.


48.4.3 Morera’s theorem
If \(f\) is continuous on a domain \(D\) and \(\oint_C f\,dz = 0\) for every closed triangle \(C\) in \(D\), then \(f\) is analytic in \(D\). (The converse of Cauchy’s theorem.)

48.5 Application: real integrals via contour integration
The general strategy — closing a real integral with a contour in the complex plane and applying Cauchy’s theorem — is developed fully in the next chapter. This example shows the technique in its simplest form.
Example. \(\displaystyle\int_{-\infty}^{\infty} \frac{dx}{1+x^2}\).
The integrand \(f(z) = 1/(1+z^2)\) has poles at \(z = \pm i\). Close the real-line integral with a large semicircle \(\Gamma_R\) of radius \(R\) in the upper half-plane, forming a closed contour \(C = [-R,R] + \Gamma_R\).
The semicircle contribution vanishes. On \(\Gamma_R\), \(|z| = R\), so \(|1+z^2| \geq R^2 - 1\) for large \(R\). The ML inequality gives: \[\left|\int_{\Gamma_R}\frac{dz}{1+z^2}\right| \leq \frac{1}{R^2-1}\cdot \pi R \to 0 \quad\text{as } R\to\infty\]
Applying Cauchy’s integral formula. Factor the denominator: \(1/(1+z^2) = [1/(z+i)]/(z-i)\). This has the form \(f(z)/(z-z_0)\) with \(f(z) = 1/(z+i)\) and \(z_0 = i\). Since \(z_0 = i\) lies inside the upper half-plane contour and \(f(z) = 1/(z+i)\) is analytic there:
\[\oint_C \frac{dz}{1+z^2} = \oint_C \frac{dz}{(z-i)(z+i)} = 2\pi i \cdot f(i) = 2\pi i \cdot \frac{1}{2i} = \pi\]
Since the semicircle contributes nothing, the real-line integral equals \(\pi\) — confirming the known result \(\arctan(x)\big|_{-\infty}^{\infty} = \pi\).






This calculation uses Cauchy’s integral formula because the integrand has a single simple pole and a purely analytic numerator. In engineering practice, the same closing-contour technique is applied via the residue theorem (Chapter 3), which handles poles of any order and multiple singularities simultaneously. The present example is the simplest special case of that general method.





Code
// VIZ 3: Cauchy integral formula — draggable pole
// Domain-coloured canvas; drag z₀ freely; smooth crossing triggers integral jump;
// KaTeX formula display; "pole on contour" warning; winding number box.
{
  const W = 360, H = 320, SCALE = 72, CX = W / 2, CY = H / 2;
  const STEPS = 360;

  const radiusCIF = Inputs.range([0.5, 2.8], { value: 1.5, step: 0.05, label: "Contour radius R" });
  const funcCIF = Inputs.select(
    ["f(z) = e^z", "f(z) = cos z", "f(z) = 1/(z+2)"],
    { value: "f(z) = e^z", label: "f(z) (numerator)" }
  );

  // Mutable pole position — shared via a plain object so canvas listeners can mutate it
  const pole = { re: 0.6, im: 0.4 };

  function evalFCIF(fname, re, im) {
    if (fname === "f(z) = e^z") return [Math.exp(re) * Math.cos(im), Math.exp(re) * Math.sin(im)];
    if (fname === "f(z) = cos z") return [Math.cos(re) * Math.cosh(im), -Math.sin(re) * Math.sinh(im)];
    const dr = re + 2, di = im, d = dr * dr + di * di;
    if (d &lt; 1e-10) return [0, 0];
    return [dr / d, -di / d];
  }

  function hslRgbCIF(h, s, l) {
    h = ((h % 1) + 1) % 1;
    const c = (1 - Math.abs(2 * l - 1)) * s;
    const x = c * (1 - Math.abs(((h * 6) % 2) - 1));
    const m = l - c / 2;
    let r = 0, g = 0, b = 0;
    if (h &lt; 1/6) { r = c; g = x; }
    else if (h &lt; 2/6) { r = x; g = c; }
    else if (h &lt; 3/6) { g = c; b = x; }
    else if (h &lt; 4/6) { g = x; b = c; }
    else if (h &lt; 5/6) { r = x; b = c; }
    else { r = c; b = x; }
    return [Math.round((r+m)*255), Math.round((g+m)*255), Math.round((b+m)*255)];
  }

  function toSxCIF(re) { return CX + re * SCALE; }
  function toSyCIF(im) { return CY - im * SCALE; }
  function fromSxCIF(px) { return (px - CX) / SCALE; }
  function fromSyCIF(py) { return -(py - CY) / SCALE; }

  function drawCIF(canvas, R, fname) {
    const ctx = canvas.getContext("2d");
    const img = ctx.createImageData(W, H);
    const data = img.data;
    const z0re = pole.re, z0im = pole.im;

    for (let px = 0; px &lt; W; px++) {
      for (let py = 0; py &lt; H; py++) {
        const re = fromSxCIF(px), im = fromSyCIF(py);
        const dr = re - z0re, di = im - z0im;
        const d2 = dr * dr + di * di;
        if (d2 &lt; 4e-4) {
          const idx = (py * W + px) * 4;
          data[idx] = 255; data[idx+1] = 255; data[idx+2] = 255; data[idx+3] = 255;
          continue;
        }
        const wr = dr / d2, wi = -di / d2;
        const arg = Math.atan2(wi, wr);
        const mag = Math.sqrt(wr*wr + wi*wi);
        const hue = (arg / (2 * Math.PI) + 1) % 1;
        const brightness = 0.48 + 0.32 * Math.tanh(Math.log(mag + 0.001) / 2);
        const [r, g, b] = hslRgbCIF(hue, 0.75, brightness);
        const idx = (py * W + px) * 4;
        data[idx] = r; data[idx+1] = g; data[idx+2] = b; data[idx+3] = 255;
      }
    }
    ctx.putImageData(img, 0, 0);

    const dist = Math.sqrt(z0re * z0re + z0im * z0im);
    const onContour = Math.abs(dist - R) &lt; 0.12;
    const inside = dist &lt; R && !onContour;

    // Contour circle
    const ox = toSxCIF(0), oy = toSyCIF(0);
    ctx.strokeStyle = onContour ? "#dc2626" : "#ffffff";
    ctx.lineWidth = 2.5;
    ctx.beginPath(); ctx.arc(ox, oy, R * SCALE, 0, 2 * Math.PI); ctx.stroke();
    ctx.fillStyle = "rgba(255,255,255,0.9)"; ctx.font = "11px sans-serif";
    ctx.fillText("C: |z| = " + R.toFixed(2), 6, 16);

    // Pole marker ×
    const px0 = toSxCIF(z0re), py0 = toSyCIF(z0im);
    ctx.strokeStyle = "#ffffff"; ctx.lineWidth = 2.5;
    ctx.beginPath(); ctx.moveTo(px0-8, py0-8); ctx.lineTo(px0+8, py0+8); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(px0+8, py0-8); ctx.lineTo(px0-8, py0+8); ctx.stroke();
    ctx.fillStyle = "rgba(255,255,255,0.9)"; ctx.font = "11px sans-serif";
    ctx.fillText("z\u2080 = " + z0re.toFixed(2) + (z0im &gt;= 0 ? "+" : "") + z0im.toFixed(2) + "i", px0 + 11, py0 + 4);

    // Winding number box
    const winding = inside ? 1 : 0;
    ctx.fillStyle = "#1e40af";
    ctx.beginPath(); ctx.roundRect(W - 92, 5, 86, 44, 5); ctx.fill();
    ctx.fillStyle = "white"; ctx.textAlign = "center";
    ctx.font = "10px sans-serif"; ctx.fillText("n(C, z\u2080)", W - 49, 21);
    ctx.font = "bold 18px sans-serif"; ctx.fillText(winding.toString(), W - 49, 41);
    ctx.textAlign = "left";

    return { inside, onContour };
  }

  // Build the container with canvas + info panel
  const container = document.createElement("div");
  container.style.cssText = "border:1px solid #e5e7eb; border-radius:8px; padding:1rem; margin:1rem 0; font-family:sans-serif;";

  const titleEl = document.createElement("div");
  titleEl.style.cssText = "font-weight:600; margin-bottom:0.5rem;";
  titleEl.textContent = "Cauchy integral formula: drag the pole z\u2080";
  container.appendChild(titleEl);

  container.appendChild(radiusCIF);
  container.appendChild(funcCIF);

  const canvas = document.createElement("canvas");
  canvas.width = W; canvas.height = H;
  canvas.style.cssText = "display:block; cursor:crosshair; border-radius:6px; margin-top:0.5rem;";
  container.appendChild(canvas);

  const infoDiv = document.createElement("div");
  infoDiv.style.cssText = "margin-top:0.5rem; font-size:0.88em;";
  container.appendChild(infoDiv);

  const noteEl = document.createElement("div");
  noteEl.style.cssText = "margin-top:0.5rem; font-size:0.82em; color:#6b7280; font-style:italic;";
