        &lt;span style="color:#6b7280; font-weight:600;"&gt;z\u2080 outside C \u2014 integrand is analytic inside&lt;/span&gt;&lt;br&gt;
        Cauchy\u2013Goursat theorem: &lt;strong&gt;\u222e f(z)/(z\u2212z\u2080) dz = 0&lt;/strong&gt;&lt;/div&gt;`;
    }
  }

  // Drag handling on canvas
  let dragging = false;
  function movePole(evt) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width, scaleY = H / rect.height;
    const cpx = (evt.clientX - rect.left) * scaleX;
    const cpy = (evt.clientY - rect.top) * scaleY;
    pole.re = Math.max(-3.5, Math.min(3.5, fromSxCIF(cpx)));
    pole.im = Math.max(-3.5, Math.min(3.5, fromSyCIF(cpy)));
