  canvas.addEventListener("mousemove", (e) =&gt; { if (dragging) movePole(e); });
  canvas.addEventListener("mouseup", () =&gt; { dragging = false; });
  canvas.addEventListener("mouseleave", () =&gt; { dragging = false; });
  canvas.addEventListener("touchstart", (e) =&gt; { e.preventDefault(); dragging = true; movePole(e.touches[0]); }, { passive: false });
  canvas.addEventListener("touchmove", (e) =&gt; { e.preventDefault(); if (dragging) movePole(e.touches[0]); }, { passive: false });
  canvas.addEventListener("touchend", () =&gt; { dragging = false; });

  radiusCIF.addEventListener("input", updateCIF);
  funcCIF.addEventListener("input", updateCIF);
  updateCIF();

  return container;
}










