  }

  function toScreen(re, im) { return [CX + re*SCALE, CY - im*SCALE]; }

  function render(fname, z0re, z0im, N) {
    const R = nearestDist(fname, z0re, z0im);
    const coeffs = taylorCoeffs(fname, z0re, z0im, N) || [];

