    ];
    const d2 = re*re+im*im; if(d2&lt;1e-8) return [NaN,NaN];
    let sumRe=0, sumIm=0;
    for(const {n, c} of activeCoeffs) {
      if(c===0) continue;
      // z^n = r^n * e^{i*n*theta}
      const r = Math.sqrt(d2);
      const theta = Math.atan2(im, re);
      const rn = Math.pow(r, n);
      if(!isFinite(rn)) continue;
      sumRe += c * rn * Math.cos(n*theta);
      sumIm += c * rn * Math.sin(n*theta);
    }
    return [sumRe, sumIm];
  }

  function hslToRgbSpec(h,s,l) {
    h=((h%1)+1)%1;
    const c=(1-Math.abs(2*l-1))*s,x=c*(1-Math.abs((h*6)%2-1)),m=l-c/2;
    let r=0,g=0,b=0;
    if(h&lt;1/6){r=c;g=x;}else if(h&lt;2/6){r=x;g=c;}else if(h&lt;3/6){g=c;b=x;}
    else if(h&lt;4/6){g=x;b=c;}else if(h&lt;5/6){r=x;b=c;}else{r=c;b=x;}
    return [Math.round((r+m)*255),Math.round((g+m)*255),Math.round((b+m)*255)];
  }

  function renderSpectrum(fname, k) {
    const coeffs = getLaurentCoeffs(fname);
    const ppCoeffs = coeffs.filter(c=&gt;c.n&lt;0&&c.c!==0).sort((a,b)=&gt;a.n-b.n);
    const kCapped = Math.min(k, ppCoeffs.length);

    // --- Bar chart ---
    const BW = 380, BH = 200;
    const barCanvas = document.createElement("canvas");
    barCanvas.width = BW; barCanvas.height = BH;
    const bctx = barCanvas.getContext("2d");
    bctx.fillStyle="#f9fafb";
    bctx.fillRect(0,0,BW,BH);

    const nVals = coeffs.map(c=&gt;c.n);
    const n0 = nVals[0], n1 = nVals[nVals.length-1];
    const totalBars = n1-n0+1;
    const barW = Math.floor((BW-40) / totalBars) - 2;
    const xOff = 30;
    const zeroY = BH - 35;
    const maxAbs = Math.max(...coeffs.map(c=&gt;Math.abs(c.c)), 0.01);
    const scaleY = (BH - 55) / maxAbs;

    // Zero line
    bctx.strokeStyle="#9ca3af"; bctx.lineWidth=1;
    bctx.beginPath(); bctx.moveTo(xOff, zeroY); bctx.lineTo(BW-10, zeroY); bctx.stroke();

    coeffs.forEach(({n,c}) =&gt; {
      const barIdx = n - n0;
      const x = xOff + barIdx * (barW+2) + 1;
      const h = Math.abs(c) * scaleY;
      const y = c &gt;= 0 ? zeroY - h : zeroY;

      // Highlight active terms
      const isPP = n &lt; 0;
      const ppIdx = ppCoeffs.findIndex(p=&gt;p.n===n);
      const isActive = isPP ? (ppIdx &gt;= 0 && ppIdx &lt; kCapped) : true;
      const isAnalytic = n &gt;= 0;

      bctx.fillStyle = isPP
        ? (isActive ? "#dc2626" : "rgba(220,38,38,0.25)")
        : (c!==0 ? "#3b82f6" : "#e5e7eb");
      bctx.fillRect(x, y, barW, Math.max(h, 1));

      // n label
      bctx.fillStyle = "#374151"; bctx.font="9px sans-serif"; bctx.textAlign="center";
      bctx.fillText(n.toString(), x+barW/2, zeroY+12);

      // c value for non-zero
