        bctx.fillText(valStr, x+barW/2, c&gt;=0 ? zeroY-h-3 : zeroY+h+20);
      }
    });
    bctx.textAlign="left";

    // Axis label
    bctx.fillStyle="#374151"; bctx.font="10px sans-serif";
    bctx.fillText("n", BW-15, zeroY+3);
    bctx.fillStyle="#dc2626"; bctx.font="10px sans-serif";
    bctx.fillText("red = principal part (n&lt;0)", 30, 14);
    bctx.fillStyle="#3b82f6";
    bctx.fillText("blue = analytic part (n≥0)", 220, 14);

    // --- Domain colouring panel ---
    const dcCanvas = document.createElement("canvas");
    dcCanvas.width=W2; dcCanvas.height=H2;
    const dctx=dcCanvas.getContext("2d");
    const img2=dctx.createImageData(W2,H2); const dd=img2.data;

    for(let px=0;px&lt;W2;px++) {
