    dctx.beginPath(); dctx.moveTo(0,dcoy); dctx.lineTo(W2,dcoy); dctx.stroke();
    dctx.beginPath(); dctx.moveTo(dcox,0); dctx.lineTo(dcox,H2); dctx.stroke();
    dctx.fillStyle="rgba(0,0,0,0.7)"; dctx.font="10px sans-serif";
    dctx.fillText(`${kCapped} pp term${kCapped===1?"":"s"} added`, 5, H2-7);

    const stepLabel = document.createElement("div");
    stepLabel.style.cssText="text-align:center; font-size:0.85em; color:#374151; margin:0.25rem 0;";
    stepLabel.textContent = kCapped === 0
      ? "Step 0: analytic part only (no principal-part terms)"
      : `Step ${kCapped}: adding c_{${ppCoeffs[kCapped-1]?.n}} term to the reconstruction`;

    const panelDiv = document.createElement("div");
