  // integrand = r^n e^{inθ} * ir e^{iθ} = i r^{n+1} e^{i(n+1)θ}
  function computeIntegralC1(n, t, STEPS) {
    const dtheta = 2*Math.PI*t / Math.max(STEPS,1);
    let sumRe=0, sumIm=0;
