    "1/((z²+1)(z²+4))   — poles at ±i, ±2i",
    "e^{iz}/(1+z²)   — Jordan's lemma case"
  ], { value: "1/(1+z²)   — poles at ±i", label: "f(z)" });

  const rSliderSM = Inputs.range([0.5, 4.5], { value: 1.5, step: 0.05, label: "Semicircle radius R" });

  const lemmaSel = Inputs.select(["ML bound", "Jordan's lemma"], {
    value: "ML bound", label: "Arc vanishing argument"
  });

  const smFuncData = {
    "1/(1+z²)   — poles at ±i": {
      poles: [{re:0,im:1,res:{re:0,im:-0.5},label:"i",half:"upper"},
              {re:0,im:-1,res:{re:0,im:0.5},label:"−i",half:"lower"}],
      eval: (re,im)=&gt;{const a=1+re*re-im*im,b=2*re*im;const d=a*a+b*b;if(d&lt;1e-10)return[NaN,NaN];return[a/d,-b/d];},
      realResult:"π", realVal:Math.PI,
      mlDegExcess: 2, jordanApplies: false,
      mlText: "Denominator deg 2, numerator deg 0 — excess 2 ≥ 2. ML bound: |1/(1+z²)| ≤ 1/(R²−1), arc length πR. Arc integral → 0.",
      jordanText: "Jordan's lemma requires an e^{iaz} oscillatory factor — not present here. Use ML bound instead.",
      note: "Upper half-plane: only z=i enclosed."
    },
    "1/((z²+1)(z²+4))   — poles at ±i, ±2i": {
      poles: [{re:0,im:1,res:{re:0,im:-1/6},label:"i",half:"upper"},
              {re:0,im:-1,res:{re:0,im:1/6},label:"−i",half:"lower"},
              {re:0,im:2,res:{re:0,im:1/12},label:"2i",half:"upper"},
              {re:0,im:-2,res:{re:0,im:-1/12},label:"−2i",half:"lower"}],
      eval: (re,im)=&gt;{
        const a1=re*re-im*im+1,b1=2*re*im,a2=re*re-im*im+4,b2=2*re*im;
        const ra=a1*a2-b1*b2,ia=a1*b2+a2*b1;const d=ra*ra+ia*ia;if(d&lt;1e-10)return[NaN,NaN];
        return[ra/d,-ia/d];
      },
      realResult:"π/6", realVal:Math.PI/6,
      mlDegExcess: 4, jordanApplies: false,
      mlText: "Denominator deg 4, numerator deg 0 — excess 4 ≥ 2. Arc integral vanishes via ML bound.",
      jordanText: "No oscillatory factor — Jordan's lemma does not apply. ML bound sufficient.",
      note: "Upper half-plane: poles at i and 2i enclosed when R &gt; 2."
    },
    "e^{iz}/(1+z²)   — Jordan's lemma case": {
      poles: [{re:0,im:1,res:{re:0,im:-0.5*Math.E/Math.E,re_override:Math.exp(-1)/(2)},label:"i",half:"upper"},
              {re:0,im:-1,res:{re:0,im:0.5},label:"−i",half:"lower"}],
      eval: (re,im)=&gt;{
        // e^{iz} * 1/(1+z^2)
        // e^{iz} = e^{i(re+iim)} = e^{-im}*(cos(re)+i*sin(re))
        const eR=Math.exp(-im)*Math.cos(re), eI=Math.exp(-im)*Math.sin(re);
        const a=1+re*re-im*im,b=2*re*im;const d=a*a+b*b;if(d&lt;1e-10)return[NaN,NaN];
        return[(eR*a+eI*b)/d,(eI*a-eR*b)/d];
      },
      realResult:"π/e (real part)", realVal:Math.PI*Math.exp(-1),
      mlDegExcess: 1, jordanApplies: true,
      mlText: "Degree excess = 1. ML bound alone gives |arc| ≤ πR/(R²−1) → 0 only at O(1/R) — barely. Better: use Jordan's lemma.",
      jordanText: "Jordan's lemma applies: integrand = e^{iz}·R(z) with R(z)→0 uniformly. Arc integral → 0 for any degree excess ≥ 1 with oscillatory factor.",
      note: "Re(∫e^{ix}/(1+x²)dx) = π/e — the hook integral in the chapter."
    }
  };

  function hslToRgbSM(h,s,l) {
    h=((h%1)+1)%1;
    const c=(1-Math.abs(2*l-1))*s,x=c*(1-Math.abs((h*6)%2-1)),m=l-c/2;
    let r=0,g=0,b=0;
    if(h&lt;1/6){r=c;g=x;}else if(h&lt;2/6){r=x;g=c;}else if(h&lt;3/6){g=c;b=x;}
    else if(h&lt;4/6){g=x;b=c;}else if(h&lt;5/6){r=x;b=c;}else{r=c;b=x;}
    return [Math.round((r+m)*255),Math.round((g+m)*255),Math.round((b+m)*255)];
  }

  function toScrSM(re,im) { return [CX_SM+re*SCALE_SM, CY_SM-im*SCALE_SM]; }

  function renderSM(fname, R, lemmaMode) {
    const fd = smFuncData[fname];

    const canvas = document.createElement("canvas");
    canvas.width=W_SM; canvas.height=H_SM;
    const ctx=canvas.getContext("2d");
    const img=ctx.createImageData(W_SM,H_SM); const data=img.data;

    // Domain colouring — only upper half-plane
    for(let px=0;px&lt;W_SM;px++) {
      for(let py=0;py&lt;H_SM;py++) {
        const re=(px-CX_SM)/SCALE_SM, im=-(py-CY_SM)/SCALE_SM;
        if(im &lt; -0.1) {
          const idx=(py*W_SM+px)*4; data[idx]=245;data[idx+1]=245;data[idx+2]=245;data[idx+3]=255; continue;
        }
        const [wr,wi]=fd.eval(re,im);
        if(!isFinite(wr)||!isFinite(wi)||isNaN(wr)) {
          const idx=(py*W_SM+px)*4; data[idx]=255;data[idx+1]=255;data[idx+2]=255;data[idx+3]=255; continue;
        }
        const arg=Math.atan2(wi,wr),mag=Math.sqrt(wr*wr+wi*wi);
        const hue=(arg/(2*Math.PI)+1)%1;
        const brightness=0.5+0.35*Math.tanh(Math.log(mag+0.001)/2);
        // Dim below real axis
        const dimFactor = im &lt; 0 ? 0.4 : 1.0;
        const [r,g,b]=hslToRgbSM(hue,0.8*dimFactor,0.5+(brightness-0.5)*dimFactor);
        const idx=(py*W_SM+px)*4; data[idx]=r;data[idx+1]=g;data[idx+2]=b;data[idx+3]=255;
      }
    }
    ctx.putImageData(img,0,0);

    const [ox,oy]=toScrSM(0,0);

    // Real axis (orange)
    ctx.strokeStyle="#f97316"; ctx.lineWidth=3;
    const [rx1]=toScrSM(-R-0.3,0); const [rx2]=toScrSM(R+0.3,0);
    ctx.beginPath(); ctx.moveTo(rx1,oy); ctx.lineTo(rx2,oy); ctx.stroke();
    // Arrow at right end
    ctx.fillStyle="#f97316";
    ctx.beginPath(); ctx.moveTo(rx2,oy); ctx.lineTo(rx2-10,oy-5); ctx.lineTo(rx2-10,oy+5); ctx.fill();
    ctx.fillStyle="#f97316"; ctx.font="10px sans-serif"; ctx.fillText("real axis (−R to R)", rx1+4, oy+16);

    // Semicircle (blue)
    ctx.strokeStyle="#3b82f6"; ctx.lineWidth=2.5;
    ctx.beginPath(); ctx.arc(ox,oy,R*SCALE_SM,Math.PI,0,false); ctx.stroke();
    // Arrow on semicircle
    const arcAngle = Math.PI/4;
    const arcX=ox+R*SCALE_SM*Math.cos(arcAngle), arcY=oy-R*SCALE_SM*Math.sin(arcAngle);
    ctx.strokeStyle="#3b82f6"; ctx.lineWidth=2;
    ctx.beginPath(); ctx.moveTo(arcX,arcY); ctx.lineTo(arcX-8,-8+arcY); ctx.lineTo(arcX+5,arcY-10); ctx.stroke();
    ctx.fillStyle="#3b82f6"; ctx.font="10px sans-serif";
    ctx.fillText(`Γ_R (R=${R.toFixed(2)})`, arcX+8, arcY-5);

    // R label on real axis
    const [rPx]=toScrSM(R,0); const [nrPx]=toScrSM(-R,0);
    ctx.fillStyle="#f97316"; ctx.font="10px sans-serif";
    ctx.fillText("R", rPx+3, oy-6); ctx.fillText("−R", nrPx-20, oy-6);

    // Poles
    fd.poles.forEach(p =&gt; {
      const [psx,psy]=toScrSM(p.re,p.im);
      const inUpper = p.im &gt; 0;
      const enclosed = inUpper && Math.sqrt(p.re*p.re+p.im*p.im) &lt; R;

      ctx.strokeStyle=enclosed?"#fbbf24":"#dc2626"; ctx.lineWidth=2.5;
      ctx.beginPath(); ctx.moveTo(psx-8,psy-8); ctx.lineTo(psx+8,psy+8); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(psx+8,psy-8); ctx.lineTo(psx-8,psy+8); ctx.stroke();
      ctx.fillStyle=enclosed?"#fbbf24":"#dc2626"; ctx.font="10px sans-serif";
      ctx.fillText(p.label, psx+10, psy+4);

      // Winding number badge for enclosed
      if(enclosed) {
        ctx.fillStyle="#1e40af"; ctx.beginPath(); ctx.arc(psx-14,psy-14,11,0,2*Math.PI); ctx.fill();
        ctx.fillStyle="white"; ctx.font="bold 9px sans-serif"; ctx.textAlign="center";
        ctx.fillText("n=1", psx-14, psy-10);
        ctx.textAlign="left";
      }
    });

    // Axis labels
    ctx.strokeStyle="rgba(255,255,255,0.5)"; ctx.lineWidth=0.8;
    ctx.beginPath(); ctx.moveTo(ox,0); ctx.lineTo(ox,H_SM); ctx.stroke();
    ctx.fillStyle="rgba(200,200,200,0.9)"; ctx.font="9px sans-serif";
    ctx.fillText("i", ox+3, oy-SCALE_SM+3); ctx.fillText("2i", ox+3, oy-2*SCALE_SM+3);

    // Result computation
    const encPoles = fd.poles.filter(p =&gt; p.im&gt;0 && Math.sqrt(p.re*p.re+p.im*p.im)&lt;R);
    let sumRe=0,sumIm=0;
    encPoles.forEach(p=&gt;{sumRe+=p.res.re;sumIm+=p.res.im;});
    const intRe=-2*Math.PI*sumIm, intIm=2*Math.PI*sumRe;

    // Result box (green)
    if(encPoles.length&gt;0) {
      ctx.fillStyle="rgba(5,150,105,0.92)";
      ctx.beginPath(); if(ctx.roundRect) ctx.roundRect(5,5,205,46,5); else ctx.rect(5,5,205,46); ctx.fill();
      ctx.fillStyle="white"; ctx.font="bold 10px sans-serif";
      ctx.fillText("∮_C f dz = 2πi × ΣRes", 10, 20);
      ctx.font="10px sans-serif";
      const resultStr=`= ${intRe.toFixed(4)} + ${intIm.toFixed(4)}i`;
      ctx.fillText(resultStr, 10, 35);
      if(fd.realVal&&encPoles.some(p=&gt;p.im&gt;0)) {
        ctx.fillStyle="#bbf7d0"; ctx.font="9px sans-serif";
        ctx.fillText(`Real integral ≈ ${Math.abs(intRe).toFixed(4)} [exact: ${fd.realResult}]`, 10, 47);
      }
    }

    // Lemma annotation
    const lemmaText = lemmaMode==="Jordan's lemma" ? fd.jordanText : fd.mlText;
    const lemmaDiv = document.createElement("div");
    lemmaDiv.style.cssText="margin-top:0.4rem; font-family:sans-serif; font-size:0.83em; padding:0.4rem 0.6rem; border-radius:4px; background:#f0f9ff; border:1px solid #bfdbfe;";
    lemmaDiv.innerHTML=`&lt;strong&gt;${lemmaMode}:&lt;/strong&gt; ${lemmaText}`;

    const infoDiv = document.createElement("div");
    infoDiv.style.cssText="margin-top:0.4rem; font-family:sans-serif; font-size:0.84em;";
    const encStr=encPoles.length===0?"none (R too small)":encPoles.map(p=&gt;p.label).join(", ");
    infoDiv.innerHTML=`&lt;strong&gt;Enclosed poles (upper half-plane):&lt;/strong&gt; ${encStr} — &lt;em&gt;${fd.note}&lt;/em&gt;`;

    const wrap=document.createElement("div");
    wrap.appendChild(canvas); wrap.appendChild(infoDiv); wrap.appendChild(lemmaDiv);
    return wrap;
  }

  const containerSM=document.createElement("div");
  containerSM.style.cssText="border:1px solid #e5e7eb; border-radius:8px; padding:1rem; margin:1rem 0;";
  const titleSM=document.createElement("div");
  titleSM.style.cssText="font-weight:600; margin-bottom:0.5rem; font-family:sans-serif;";
  titleSM.textContent="Semicircle contour closure: real integrals via the upper half-plane";
  containerSM.appendChild(titleSM);
  containerSM.appendChild(funcSelSM);
  containerSM.appendChild(rSliderSM);
  containerSM.appendChild(lemmaSel);
  const vizDivSM=document.createElement("div");
  containerSM.appendChild(vizDivSM);
  const noteSM=document.createElement("div");
  noteSM.style.cssText="margin-top:0.5rem; font-size:0.82em; color:#6b7280; font-style:italic;";
  noteSM.textContent="Orange line = real axis −R to R; blue arc = semicircle Γ_R. Domain colouring shows f(z) in the upper half-plane. Red × = poles not yet enclosed; gold × = enclosed poles (winding number n=1 shown). Green box shows the integral result as R grows past each pole. Toggle the arc-vanishing argument between ML bound and Jordan's lemma.";
  containerSM.appendChild(noteSM);

  function updateSM(){
    vizDivSM.innerHTML="";
    vizDivSM.appendChild(renderSM(funcSelSM.value, parseFloat(rSliderSM.value), lemmaSel.value));
  }
  funcSelSM.addEventListener("input",updateSM);
  rSliderSM.addEventListener("input",updateSM);
  lemmaSel.addEventListener("input",updateSM);
  updateSM();

  return containerSM;
}







The residue theorem and Laurent series complete the core tools of complex integration. The next chapter takes a different direction: conformal mapping uses analytic functions to deform geometry — turning complicated domains into simple ones where Laplace’s equation can be solved directly.

