        angleColour = "#dc2626";
        critNote = "f′(z₀) ≈ 0 — conformality fails here.";
      } else {
        // Compute angle between tangent image vectors
        // Red arm tangent in z: (1,0); image tangent = fp * (1,0) = fp
        const tRed = [fpz[0], fpz[1]];
        // Blue arm tangent in z: (0,1) (= i); image tangent = fp * i = (-fpz[1], fpz[0])
        const tBlue = [-fpz[1], fpz[0]];
        const dot = tRed[0]*tBlue[0] + tRed[1]*tBlue[1];
        const mR = Math.sqrt(tRed[0]**2 + tRed[1]**2);
        const mB = Math.sqrt(tBlue[0]**2 + tBlue[1]**2);
        const cosA = Math.max(-1, Math.min(1, dot / (mR * mB)));
        const angleDeg = Math.acos(cosA) * 180 / Math.PI;
        const isCrit = Math.abs(angleDeg - 90) &gt; 5;
        angleStr = `${angleDeg.toFixed(1)}°`;
        angleColour = isCrit ? "#dc2626" : "#059669";
        critNote = isCrit ? "critical point — angle doubled" : "conformal (angle preserved)";
      }

      const fpArg = Math.atan2(fpz[1], fpz[0]) * 180 / Math.PI;

      readout.innerHTML = `
        &lt;span style="color:${angleColour}; font-weight:600;"&gt;Angle between image arms: ${angleStr}&lt;/span&gt;
