        &nbsp;|&nbsp;
        arg f′(z₀) = &lt;strong&gt;${fpArg.toFixed(1)}°&lt;/strong&gt; (rotation applied to both arms)
      `;
      return;
    }

    readout.innerHTML = `
      &lt;span style="color:${angleColour}; font-weight:600;"&gt;${angleStr}&lt;/span&gt;
      ${critNote ? `&lt;br&gt;&lt;span style="color:${angleColour}; font-size:0.92em;"&gt;${critNote}&lt;/span&gt;` : ""}
    `;
  }

