  z0ReSlider.addEventListener("input", () =&gt; { z0 = [z0ReSlider.value, z0[1]]; render(); });
  z0ImSlider.addEventListener("input", () =&gt; { z0 = [z0[0], z0ImSlider.value]; render(); });

