  // dF/dz = U(1 - r²/z²) + i*Gamma/(2*pi*z)
  // vx = Re(dF/dz), vy = -Im(dF/dz)
  function complexVelocity(zr, zi, r, circ) {
    const d2 = zr*zr + zi*zi; if(d2&lt;1e-12)return[NaN,NaN];
    const z2r=zr*zr-zi*zi,z2i=2*zr*zi; const z2d=z2r*z2r+z2i*z2i;
