    // x² - y² = C; parametrise: x = sqrt(C + y²) for C&gt;0
    const phiVals = [-1.5, -0.8, 0.2, 0.8, 1.5, 2.2];
    phiVals.forEach(C=&gt;{
      let d="";let prev=false;
      for(let k=0;k&lt;=80;k++){
        const y=k*2.3/80;
        const x2=C+y*y;
        if(x2&lt;0.001)continue;
        const x=Math.sqrt(x2);
        if(x&gt;2.5)continue;
        const[px,py]=ts_fq(x,y);
        if(!prev){d=`M ${px} ${py}`;prev=true;}else d+=`L ${px} ${py}`;
      }
      if(d)mkPath(leftSvg,d,mode==="Fluid flow"?"#f97316":"#3b82f6",1.2,"4,3");
    });

    // Tracer dot: moves along streamline Ψ = 1.2, parameterised by angle
    // On streamline 2xy = C: (t/sqrt(2), C/(sqrt(2)*t)) for t in [eps, ...]
    const C_tracer = 1.2;
    const tVal = 0.4 + tracerT * 1.6; // t goes from 0.4 to 2.0
    const tx_z = tVal;
    const ty_z = C_tracer / (2 * tVal);
    if(ty_z &gt; 0 && ty_z &lt; 2.5 && tx_z &lt; 2.5){
      const[dpx,dpy]=ts_fq(tx_z,ty_z);
      mkDot(leftSvg,dpx,dpy,"#fbbf24");
    }

    // Axis labels
    mkTxt(leftSvg,ts_fq(2.4,0)[0]+2,ts_fq(0,0)[1],"Re z","#6b7280","10");
    mkTxt(leftSvg,ts_fq(0,2.1)[0]+4,ts_fq(0,2.1)[1],"Im z","#6b7280","10");
    mkTxt(leftSvg,5,15,"z-plane (first quadrant)","#6b7280","10");

    const wallLabel = mode==="Fluid flow"?"solid walls":"conductor boundaries";
    mkTxt(leftSvg,ox+6,oy-6,wallLabel,"#6b7280","9");

    // --- RIGHT: w-plane, upper half-plane ---
    const WSCALE=40, WCX=WP/2, WCY=HP-20;
    const [wox,woy]=ts_uhp(0,0,WCX,WCY,WSCALE);

    // Real axis (solid wall in w-plane)
    mkLine(rightSvg,10,woy,WP-10,woy,"#6b7280",2.5);

    // w = z² maps: Ψ_w = Im(w) = Im(z²) = 2xy = Ψ_z (same value!)
    // So streamlines Im(w) = C are horizontal lines Im(w) = C
    psiVals.forEach(C=&gt;{
      const [,py]=ts_uhp(0,C,WCX,WCY,WSCALE);
      if(py&lt;5||py&gt;HP-5)return;
      mkLine(rightSvg,10,py,WP-10,py,mode==="Fluid flow"?"#3b82f6":"#f97316",1.5,mode==="Fluid flow"?null:"4,3");
      mkTxt(rightSvg,WP-28,py-3,`Ψ=${C.toFixed(1)}`,"rgba(59,130,246,0.7)","8");
    });

    // Equipotentials Φ_w = Re(w) = Re(z²) = x²-y² = C are vertical lines Re(w) = C
    phiVals.forEach(C=&gt;{
      const[px]=ts_uhp(C,0,WCX,WCY,WSCALE);
      if(px&lt;5||px&gt;WP-5)return;
      mkLine(rightSvg,px,5,px,woy,mode==="Fluid flow"?"#f97316":"#3b82f6",1.2,"4,3");
    });

    // Tracer in w-plane: w = z² for the z-tracer
    const tw_r = tx_z*tx_z - ty_z*ty_z;
    const tw_i = 2*tx_z*ty_z;
    const[wpx,wpy]=ts_uhp(tw_r,tw_i,WCX,WCY,WSCALE);
    if(wpx&gt;5&&wpx&lt;WP-5&&wpy&gt;5&&wpy&lt;woy)mkDot(rightSvg,wpx,wpy,"#fbbf24");

    // Labels
    mkTxt(rightSvg,5,15,"w-plane (upper half-plane)","#6b7280","10");
    mkTxt(rightSvg,WP/2,HP-5,"real axis (boundary)","#6b7280","9","middle");

    // Readout
    const psiLabel = mode==="Fluid flow"?"stream function Ψ":"flux function Ψ";
    const phiLabel = mode==="Fluid flow"?"velocity potential Φ":"electrostatic potential Φ";
    const blueLabel = mode==="Fluid flow"?"streamlines (blue)":"equipotentials (blue)";
    const orangeLabel = mode==="Fluid flow"?"equipotentials (orange dashed)":"field lines (orange dashed)";
    readoutDiv.innerHTML=`&lt;strong&gt;${mode}:&lt;/strong&gt; ${blueLabel}: ${psiLabel} = 2xy = C &nbsp;|&nbsp; ${orangeLabel}: ${phiLabel} = x²−y² = C&lt;br&gt;
      &lt;span style="color:#6b7280;font-size:0.9em;"&gt;w = z² maps the first-quadrant corner flow to horizontal/vertical uniform flow in the upper half-plane. Both sets of curves are rectangular hyperbolae in z but become straight lines in w.&lt;/span&gt;`;
  }

  // Animate tracer along streamline
  function runAnimation(){
    if(animating)return;
    animating=true;tracerT=0;
    const startTime=performance.now(),dur=3000;
    function step(now){
      tracerT=((now-startTime)/dur)%1;
      render();
      animReq=requestAnimationFrame(step);
    }
    animReq=requestAnimationFrame(step);
    // Stop after 3 cycles
    setTimeout(()=&gt;{animating=false;if(animReq)cancelAnimationFrame(animReq);},9000);
  }

  animBtn.addEventListener("input",()=&gt;{if(!animating)runAnimation();});
  modeToggle.addEventListener("input",()=&gt;render());

  render();
  return container;
}

