  const alpha = 1;
  function stepHeat(dx, dt, steps) {
    const n = Math.round(1 / dx);
    let u = Array.from({ length: n + 1 }, (_, j) =&gt; {
      const z = (j * dx - 0.5) / 0.08;
      return Math.exp(-(z * z));
    });
    u[0] = 0; u[n] = 0;
    const r = alpha * dt / (dx * dx);
    for (let s = 0; s &lt; steps; s++) {
      const next = u.slice();
      for (let j = 1; j &lt; n; j++) next[j] = r * u[j - 1] + (1 - 2 * r) * u[j] + r * u[j + 1];
      next[0] = 0; next[n] = 0;
      u = next;
    }
    return { u, r, n };
  }

