      area.setAttribute("points",`${sx(info.xs[0])},${sy(0)} ${pts} ${sx(info.xs[info.xs.length-1])},${sy(0)}`);
      area.setAttribute("fill",ACCENT); area.setAttribute("fill-opacity","0.35");
