      const c = svgEl("line");
      c.setAttribute("x1", String(sx(x)));
      c.setAttribute("y1", String(sy(y)));
      c.setAttribute("x2", String(sx(x)));
      c.setAttribute("y2", String(sy(b0 + b1 * x)));
      c.setAttribute("stroke", resid &gt;= 0 ? "#93c5fd" : "#fca5a5");
