      swatch.style.cssText = `display:inline-block; width:1.6rem; height:0; border-top:3px ${dash ? "dashed" : "solid"} ${color};`;
    }
    const label = document.createElement("span");
    label.textContent = text;
    item.append(swatch, label);
    return item;
  }
  legend.append(
    legendItem(BLUE, false, "true state"),
    legendItem(AMBER, false, "measurements", true),
    legendItem(GREY, true, "prior estimate"),
    legendItem(GREEN, false, "updated estimate")
  );

