    measCard.textContent = meas[last].y.toFixed(2);
    priorCard.textContent = prior[last].y.toFixed(2);
    postCard.textContent = post[last].y.toFixed(2);
    innovationCard.textContent = post[last].innovation &gt;= 0
      ? `+${post[last].innovation.toFixed(2)}`
      : post[last].innovation.toFixed(2);
    innovationCard.style.color = Math.abs(post[last].innovation) &gt; noise ? RED : GREY;

    note.textContent = gain &gt; 0.7
      ? "High K makes the estimate chase the measurements closely, which improves responsiveness but also passes more sensor noise into the estimate."
      : gain &lt; 0.3
        ? "Low K makes the estimate trust the prior strongly, which smooths noise but can lag behind real changes in the hidden state."
        : "Intermediate K balances responsiveness against noise suppression: the estimate moves toward the data without fully inheriting measurement jitter.";
  }

  noiseSlider.addEventListener("input", render);
  gainSlider.addEventListener("input", render);

  container.append(controls, readout, svg, legend, note);
  render();
  return container;
}

63.5 Worked example 1: one-step scalar filter
Suppose the prior estimate of a temperature is \(\hat{x}^- = 18\) degrees, a new sensor reading is \(y = 20\) degrees, and the update weight is \(K = 0.3\). Then
\[\hat{x}^+ = \hat{x}^- + K(y - \hat{x}^-)
= 18 + 0.3(20 - 18)
= 18 + 0.6
= 18.6\]
The updated estimate moves toward the measurement, but does not jump all the way there. That is exactly what you want when the sensor is informative but not perfect.
If the sensor were known to be extremely reliable, a larger \(K\) would make sense. If the measurement were very noisy, a smaller \(K\) would be more honest.


